/// <reference lib="dom" />
/// <reference lib="es2020" />
/* eslint-env browser */
/* global window, document, HTMLElement, customElements, console, Image, requestAnimationFrame, cancelAnimationFrame, setTimeout, clearTimeout */
/* Viviris & Co. immersive Custom Element for Wix Studio. */
(function(){
  'use strict';
  const TAG_NAME = 'viviris-immersive';
  const THREE_URL = 'https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js';
  const STYLE_TEXT = "\n:host{\n  display:block;\n  position:relative;\n  width:100%;\n  min-height:100vh;\n  margin:0!important;\n  padding:0!important;\n  background:#04060e;\n  color:#dfe6ff;\n  overflow:visible;\n}\n:host *{box-sizing:border-box;}\n.viviris-custom-element-root:not(.user-entered) #welcome{display:flex!important;opacity:1!important;visibility:visible!important;pointer-events:auto!important;}\n.viviris-custom-element-root:not(.user-entered) #brand,.viviris-custom-element-root:not(.user-entered) #soundBtn,.viviris-custom-element-root:not(.user-entered) #chapNav,.viviris-custom-element-root:not(.user-entered) #scrollHint{opacity:0!important;pointer-events:none!important;}\n.viviris-custom-element-root{\n  position:relative;\n  width:100%;\n  min-height:100vh;\n  background:#04060e;\n  color:#dfe6ff;\n  overflow:visible;\n  margin-top:0!important;\n  padding-top:0!important;\n  isolation:isolate;\n}\n.viviris-custom-element-root canvas,\n.viviris-custom-element-root img,\n.viviris-custom-element-root video{max-width:none;}\n/* Wix Custom Element state mirrors. Use the real IDs generated below. */\n.viviris-custom-element-root.entered #brand,\n.viviris-custom-element-root.entered #soundBtn,\n.viviris-custom-element-root.entered #chapNav,\n.viviris-custom-element-root.entered #hud{opacity:.85!important;}\n.viviris-custom-element-root.entered #welcome.gone{opacity:0!important;visibility:hidden!important;pointer-events:none!important;}\n.viviris-custom-element-root.entered #landing{visibility:visible!important;}\n\n\n:root{\r\n  --abyss:#04060e;\r\n  --deepsea:#071226;\r\n  --iris:#8b7bff;\r\n  --iris-soft:#c4bdff;\n  --pink:#ff4fa3;\r\n  --moon:#dfe6ff;\r\n  --dim:#a8b2d4;\n  --line:rgba(139,123,255,.18);\r\n  --serif:\"Shippori Mincho\",\"Hiragino Mincho ProN\",\"Yu Mincho\",\"Noto Serif JP\",serif;\r\n  --gothic:\"Zen Kaku Gothic New\",\"Hiragino Kaku Gothic ProN\",\"Yu Gothic\",\"Noto Sans JP\",sans-serif;\r\n  --mono:ui-monospace,\"SFMono-Regular\",\"Cascadia Mono\",\"Roboto Mono\",monospace;\r\n}\r\n*{margin:0;padding:0;box-sizing:border-box}\nbody{\n  background:var(--abyss);\r\n  color:var(--moon);\r\n  font-family:var(--gothic);\r\n  overflow-x:hidden;\r\n  -webkit-font-smoothing:antialiased;\r\n}\n::selection{background:var(--iris);color:#04060e}\na:focus-visible,button:focus-visible{\n  outline:2px solid #f8fbff;outline-offset:4px;\n  box-shadow:0 0 0 6px rgba(139,123,255,.28),0 0 28px rgba(126,217,255,.38);\n}\n.skipLink{\n  position:fixed;left:1rem;top:1rem;z-index:120;\n  transform:translateY(-180%);padding:.8rem 1rem;border-radius:999px;\n  background:#f8fbff;color:#04060e;text-decoration:none;font-size:.78rem;letter-spacing:.08em;\n  transition:transform .25s ease;\n}\n.skipLink:focus-visible{transform:none}\n.srOnly{\n  position:absolute!important;width:1px!important;height:1px!important;padding:0!important;margin:-1px!important;\n  overflow:hidden!important;clip:rect(0,0,0,0)!important;white-space:nowrap!important;border:0!important;\n}\n\r\n#gl{position:fixed;inset:0;width:100%;height:100%;z-index:0;display:block}\r\n\r\n/* ---------- game HUD frame ---------- */\r\n.corner{position:fixed;width:26px;height:26px;z-index:38;opacity:0;transition:opacity 1s 1s;pointer-events:none}\r\nbody.entered .corner{opacity:.55}\r\n.corner.tl{top:14px;left:14px;border-top:1px solid var(--iris);border-left:1px solid var(--iris)}\r\n.corner.tr{top:14px;right:14px;border-top:1px solid var(--iris);border-right:1px solid var(--iris)}\r\n.corner.bl{bottom:14px;left:14px;border-bottom:1px solid var(--iris);border-left:1px solid var(--iris)}\r\n.corner.br{bottom:14px;right:14px;border-bottom:1px solid var(--iris);border-right:1px solid var(--iris)}\r\n#hud{\r\n  position:fixed;right:1.8rem;bottom:1.6rem;z-index:38;\r\n  font-family:var(--mono);font-size:.6rem;letter-spacing:.22em;\r\n  color:var(--dim);text-align:right;line-height:1.9;\r\n  opacity:0;transition:opacity 1s 1.2s;pointer-events:none;\r\n}\r\nbody.entered #hud{opacity:.85}\r\n#hud b{color:var(--iris-soft);font-weight:400}\r\n#hud .blink{animation:blink 1.4s steps(2) infinite}\r\n@keyframes blink{50%{opacity:.15}}\r\n\r\n/* ---------- Welcome ---------- */\r\n#welcome{\r\n  position:fixed;inset:0;z-index:100;\r\n  background:radial-gradient(120% 120% at 50% 120%, #0a1430 0%, #04060e 55%, #02030a 100%);\r\n  display:flex;flex-direction:column;align-items:center;justify-content:center;\r\n  gap:2.2rem;text-align:center;\r\n  transition:opacity 1.4s ease, visibility 1.4s;\r\n}\r\n#welcome.gone{opacity:0;visibility:hidden;pointer-events:none}\r\n.w-mark{\r\n  font-family:var(--serif);\r\n  font-size:clamp(2.4rem,6vw,4.6rem);\r\n  letter-spacing:.18em;font-weight:500;color:var(--moon);\r\n  text-shadow:0 0 40px rgba(139,123,255,.45);\r\n  animation:breathe 5s ease-in-out infinite;\r\n}\r\n.w-mark em{font-style:normal;background:linear-gradient(90deg,#8b7bff,#ff4fa3,#ffd166,#4fd1ff,#8b7bff);\r\n  background-size:300% 100%;-webkit-background-clip:text;background-clip:text;color:transparent;\r\n  animation:prism 9s linear infinite}\r\n@keyframes prism{to{background-position:300% 0}}\r\n@keyframes breathe{0%,100%{opacity:.92}50%{opacity:1}}\r\n.w-sub{font-family:var(--serif);font-size:clamp(.85rem,1.7vw,1.05rem);letter-spacing:.42em;color:var(--dim);\r\n  display:flex;flex-direction:column;align-items:center;gap:1rem}\r\n.w-sub .en{font-family:var(--mono);font-size:.58em;letter-spacing:.62em;text-indent:.62em;color:var(--iris-soft);\r\n  text-shadow:0 0 16px rgba(139,123,255,.5)}\r\n#enterBtn{\r\n  margin-top:1rem;font-family:var(--gothic);letter-spacing:.5em;text-indent:.5em;\r\n  font-size:.78rem;color:var(--moon);background:transparent;border:1px solid var(--line);\r\n  padding:1.05rem 3.4rem;cursor:pointer;border-radius:999px;transition:border-color .45s,color .45s,box-shadow .45s;\r\n  position:relative;overflow:hidden;will-change:transform;\r\n}\r\n#enterBtn:hover,#enterBtn:focus-visible{\n  border-color:var(--iris);color:#fff;\n  box-shadow:0 0 32px rgba(139,123,255,.35), inset 0 0 18px rgba(139,123,255,.15),0 0 0 6px rgba(139,123,255,.2);\n}\n.w-note{font-size:.68rem;letter-spacing:.22em;color:#525b7d}\r\n.w-ring{\r\n  position:absolute;width:min(72vmin,560px);height:min(72vmin,560px);border-radius:50%;\r\n  border:1px solid rgba(139,123,255,.12);animation:spinSlow 26s linear infinite;pointer-events:none;\r\n}\r\n.w-ring::before{content:\"\";position:absolute;inset:-1px;border-radius:50%;border:1px solid transparent;\r\n  border-top-color:rgba(255,79,163,.45);border-right-color:rgba(139,123,255,.4);filter:blur(.4px)}\r\n@keyframes spinSlow{to{transform:rotate(360deg)}}\r\n\r\n/* ---------- chrome ---------- */\r\n#brand{position:fixed;top:1.6rem;left:1.8rem;z-index:40;font-family:var(--serif);\r\n  letter-spacing:.2em;font-size:.95rem;color:var(--moon);text-decoration:none;opacity:0;transition:opacity 1s .6s}\r\n#soundBtn{position:fixed;top:1.5rem;right:1.8rem;z-index:40;background:transparent;border:1px solid var(--line);\r\n  color:var(--dim);font-size:.62rem;letter-spacing:.3em;text-indent:.3em;padding:.55rem 1.1rem;border-radius:999px;\r\n  cursor:pointer;transition:.3s;opacity:0}\r\n#soundBtn.on{color:var(--moon);border-color:var(--iris)}\r\nbody.entered #brand,body.entered #soundBtn{opacity:1}\r\n.eq{display:inline-flex;gap:2px;align-items:flex-end;height:9px;margin-right:.5em;vertical-align:-1px}\r\n.eq i{width:2px;background:currentColor;height:3px}\r\n#soundBtn.on .eq i{animation:eq .9s ease-in-out infinite}\r\n#soundBtn.on .eq i:nth-child(2){animation-delay:.2s}\r\n#soundBtn.on .eq i:nth-child(3){animation-delay:.45s}\r\n@keyframes eq{0%,100%{height:3px}50%{height:9px}}\r\n\r\n#chapNav{position:fixed;left:1.7rem;top:50%;transform:translateY(-50%);z-index:40;\r\n  display:flex;flex-direction:column;gap:1.5rem;opacity:0;transition:opacity 1s .8s}\r\nbody.entered #chapNav{opacity:1}\r\n.cn{display:flex;align-items:center;gap:.7rem;cursor:pointer;background:none;border:none;color:var(--dim);padding:0}\r\n.cn b{width:6px;height:6px;border-radius:50%;background:currentColor;opacity:.5;transition:.4s;flex:none;position:relative}\n.cn b::after{content:\"\";position:absolute;inset:-5px;border:1px solid currentColor;border-radius:50%;opacity:0;transform:scale(.65);transition:.4s}\n.cn span{font-size:.62rem;letter-spacing:.32em;writing-mode:vertical-rl;font-family:var(--serif);\r\n  opacity:0;transform:translateX(-4px);transition:.4s;max-height:0}\r\n.cn.act{color:var(--iris-soft)}\n.cn.act b{width:9px;height:9px;opacity:1;box-shadow:0 0 12px var(--iris),0 0 0 3px rgba(248,251,255,.12)}\n.cn.act b::after{opacity:.75;transform:scale(1)}\n.cn.act span{opacity:1;transform:none;max-height:9rem}\n\r\n#scrollHint{position:fixed;bottom:2rem;left:50%;transform:translateX(-50%);z-index:30;\r\n  font-size:.68rem;letter-spacing:.5em;text-indent:.5em;color:#f3fbff;opacity:0;\r\n  text-shadow:0 0 10px rgba(255,255,255,.72),0 0 18px rgba(79,209,255,.72),0 0 32px rgba(139,123,255,.48);\r\n  transition:opacity .8s ease, filter .8s ease;filter:blur(10px);display:flex;flex-direction:column;align-items:center;gap:.6rem}\r\nbody.entered #scrollHint{opacity:0}\r\n#scrollHint::after{content:\"\";width:1px;height:50px;background:linear-gradient(to bottom,#fff,rgba(79,209,255,.92),transparent);\r\n  box-shadow:0 0 14px rgba(255,255,255,.7),0 0 24px rgba(79,209,255,.7);animation:drop 1.8s ease-in-out infinite}\r\n@keyframes drop{0%{transform:scaleY(0);transform-origin:top}55%{transform:scaleY(1);transform-origin:top}56%{transform-origin:bottom}100%{transform:scaleY(0);transform-origin:bottom}}\r\n\r\n/* ---------- captions ---------- */\r\n.cap{position:fixed;inset:0;z-index:10;pointer-events:none;display:flex;align-items:center;justify-content:center;opacity:0}\r\n.cap-in{max-width:min(760px,88vw);padding:2.6rem 2.5rem;border-radius:18px;\r\n  background:linear-gradient(135deg,rgba(4,6,14,.78),rgba(9,13,32,.62));\r\n  border:1px solid rgba(185,200,255,.22);\r\n  backdrop-filter:blur(13px) saturate(1.08);-webkit-backdrop-filter:blur(13px) saturate(1.08);\r\n  box-shadow:0 34px 92px -30px rgba(0,0,0,.92),inset 0 1px 0 rgba(255,255,255,.08)}\r\n.cap .ch-no{font-size:.62rem;letter-spacing:.55em;color:var(--iris-soft);margin-bottom:1.6rem;font-family:var(--mono)}\r\n.cap h2{font-family:var(--serif);font-weight:500;font-size:clamp(1.2rem,2.45vw,1.9rem);\r\n  letter-spacing:.1em;line-height:1.88;margin-bottom:1.8rem;color:#fff;\r\n  word-break:keep-all;line-break:strict;text-wrap:balance;\r\n  text-shadow:0 2px 22px rgba(0,0,0,1),0 0 18px rgba(255,255,255,.14)}\r\n.cap p{font-family:var(--serif);font-size:clamp(.82rem,1.3vw,.95rem);line-height:2.5;\r\n  letter-spacing:.08em;color:#edf3ff;word-break:keep-all;line-break:strict;\r\n  text-shadow:0 1px 16px rgba(0,0,0,1),0 0 10px rgba(255,255,255,.12)}\r\n.cap .tate{position:absolute;right:clamp(1.2rem,6vw,5rem);top:50%;transform:translateY(-50%);\r\n  writing-mode:vertical-rl;font-family:var(--serif);font-size:clamp(1rem,2vw,1.4rem);\r\n  letter-spacing:.38em;color:rgba(223,230,255,.4);white-space:nowrap;overflow:visible}\r\n#cap4 h2 em{font-style:normal;color:#fff;text-shadow:0 2px 22px rgba(0,0,0,1),0 0 18px rgba(255,255,255,.16)}\r\n\r\n#story{height:640vh;position:relative;z-index:1}\r\n\r\n/* ============================================================\r\n   CHAPTER 5 — landing. Canvas stays alive behind (.86 alpha)\r\n   ============================================================ */\r\n#landing{\r\n  position:relative;z-index:5;\r\n  background:linear-gradient(to bottom, rgba(4,6,14,0) 0%, rgba(4,6,14,.7) 9%, rgba(4,6,14,.8) 16%);\r\n  padding-top:18vh;\r\n}\r\n.sec{max-width:1080px;margin:0 auto;padding:7rem clamp(1.4rem,5vw,3rem);position:relative;perspective:1200px}\r\n.sec#works{padding-top:8.5rem;padding-bottom:8.5rem}\r\n/* per-card scroll rotation handled in JS; grids keep 3D context */\r\n.tiltGroup{transform-style:preserve-3d}\r\n/* glass game-UI surfaces */\r\n.rcard,.md,.bg-card,.mb,.commerceBox,.metric{backdrop-filter:blur(9px) saturate(1.25);-webkit-backdrop-filter:blur(9px) saturate(1.25)}\n.eyebrow{font-family:var(--mono);font-size:.62rem;letter-spacing:.8em;color:var(--iris-soft);margin-bottom:1.4rem;\r\n  opacity:0;transform:translateY(10px);transition:all 1s .1s}\r\n.rv.in .eyebrow{opacity:1;transform:none;letter-spacing:.5em}\r\n.sec h3{font-family:var(--serif);font-weight:500;font-size:clamp(1.35rem,2.6vw,1.95rem);\r\n  letter-spacing:.12em;line-height:1.95;margin-bottom:1.6rem}\r\n.sec .lead{font-family:var(--serif);line-height:2.4;letter-spacing:.1em;color:var(--moon);\r\n  font-size:clamp(.86rem,1.4vw,.98rem);max-width:46em}\r\n.sec h3,.sec .lead,#philosophy blockquote,.rcard h4,.rcard p,.md h4,.md p,.bg-card h4,.bg-card p,.mb h4,.mb p,.commerceBox p,.metric,.moreLink,.cta{\n  word-break:keep-all;line-break:strict;text-wrap:balance;\r\n  text-shadow:0 2px 18px rgba(0,0,0,.82),0 0 14px rgba(255,255,255,.08);\r\n}\r\n.rcard,.md,.bg-card,.mb,.commerceBox,.metric{\n  background-color:rgba(6,9,22,.54);\r\n  box-shadow:0 24px 70px -38px rgba(0,0,0,.9),inset 0 1px 0 rgba(255,255,255,.06);\r\n}\r\n\r\n/* char split: blur-bloom reveal (にじむ発光) */\r\n.st .ch{display:inline-block;opacity:0;will-change:transform,filter}\r\n.st.in .ch{animation:chIn 1.05s cubic-bezier(.2,.8,.2,1) both;animation-delay:calc(var(--i)*26ms)}\r\n@keyframes chIn{\r\n  0%{opacity:0;transform:translateY(.65em) scale(1.12);filter:blur(9px);\r\n     text-shadow:0 0 26px rgba(139,123,255,.0)}\r\n  45%{opacity:1;filter:blur(2px);\r\n     text-shadow:0 0 22px rgba(139,123,255,.85),0 0 44px rgba(255,79,163,.45)}\r\n  100%{opacity:1;transform:none;filter:blur(0);\r\n     text-shadow:0 0 0 rgba(139,123,255,0)}\r\n}\r\n.rv.in .eyebrow{text-shadow:0 0 14px rgba(139,123,255,.55)}\r\n.lead.fd{opacity:0;transform:translateY(22px);transition:all 1.1s .5s cubic-bezier(.2,.8,.2,1)}\r\n.rv.in .lead.fd{opacity:1;transform:none}\r\n\r\n/* rule line draws itself */\r\n.rule{height:1px;max-width:1080px;margin:0 auto;position:relative;overflow:hidden}\r\n.rule::before{content:\"\";position:absolute;inset:0;\r\n  background:linear-gradient(90deg,transparent,var(--line),transparent);\r\n  transform:scaleX(0);transition:transform 1.4s cubic-bezier(.2,.8,.2,1)}\r\n.rule.in::before{transform:scaleX(1)}\r\n\r\n/* ---------- vow ---------- */\r\n#vow{text-align:center;padding-top:4rem}\r\n#vow .lead{margin:0 auto}\r\n#vow h3 .spark{color:#f7fbff;text-shadow:0 2px 20px rgba(0,0,0,.9),0 0 16px rgba(185,200,255,.4)}\r\n\r\n/* ---------- philosophy ---------- */\r\n#philosophy{overflow:hidden}\r\n#philosophy .ghost{\r\n  position:absolute;right:-2rem;top:50%;transform:translateY(-50%);\r\n  font-family:var(--serif);writing-mode:vertical-rl;font-size:clamp(7rem,16vw,13rem);\r\n  color:transparent;-webkit-text-stroke:1px rgba(139,123,255,.1);\r\n  letter-spacing:.2em;pointer-events:none;user-select:none;white-space:nowrap;\r\n  transition:transform .2s linear;\r\n}\r\n#philosophy blockquote{\r\n  font-family:var(--serif);font-size:clamp(1rem,2vw,1.38rem);\r\n  line-height:2.4;letter-spacing:.12em;border:none;position:relative;z-index:2;\r\n}\r\n#philosophy blockquote strong{color:var(--pink);font-weight:500}\r\n#philosophy blockquote b{color:var(--iris-soft);font-weight:500}\r\n#philosophy .x10{\r\n  display:inline-block;font-size:1.55em;line-height:1;color:var(--pink);\r\n  text-shadow:0 0 20px rgba(255,79,163,.45);\r\n}\r\n#philosophy .orbit{\r\n  position:absolute;left:-3rem;top:-2rem;width:200px;height:200px;border-radius:50%;\r\n  border:1px dashed rgba(139,123,255,.18);animation:spinSlow 30s linear infinite;pointer-events:none;\r\n}\r\n#philosophy .orbit::before{content:\"\";position:absolute;top:-3px;left:50%;width:6px;height:6px;border-radius:50%;\r\n  background:var(--pink);box-shadow:0 0 14px var(--pink)}\r\n\r\n/* ---------- marquee ---------- */\r\n.marquee{overflow:hidden;border-top:1px solid var(--line);border-bottom:1px solid var(--line);\r\n  padding:1.1rem 0;position:relative;z-index:5;background:rgba(4,6,14,.5)}\r\n.mq-track{display:flex;gap:4rem;width:max-content;animation:mq 38s linear infinite;will-change:transform}\r\n.mq-track span{font-family:var(--serif);font-size:.78rem;letter-spacing:.42em;color:rgba(235,242,255,.58);white-space:nowrap}\r\n.mq-track span em{font-style:normal;color:#dfe8ff;text-shadow:0 0 16px rgba(139,123,255,.5)}\r\n@keyframes mq{to{transform:translateX(-50%)}}\r\n\r\n/* ---------- reasons ---------- */\r\n.cards3{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:1.2rem;margin-top:3rem;perspective:1100px}\r\n.rcard{\r\n  border:1px solid var(--line);border-radius:14px;padding:2.2rem 1.8rem;\r\n  background:linear-gradient(160deg,rgba(139,123,255,.06),rgba(255,79,163,.03) 60%,transparent);\r\n  position:relative;overflow:hidden;transform-style:preserve-3d;\r\n  transition:border-color .45s;will-change:transform;\r\n}\r\n.rcard::after{content:\"\";position:absolute;inset:0;opacity:0;transition:.45s;\r\n  background:radial-gradient(420px 200px at var(--mx,50%) var(--my,0%), rgba(139,123,255,.16), transparent 70%);\r\n  pointer-events:none}\r\n.rcard:hover{border-color:rgba(139,123,255,.45)}\r\n.rcard:hover::after{opacity:1}\r\n.rcard h4{font-family:var(--serif);font-weight:500;letter-spacing:.12em;font-size:1.05rem;margin-bottom:1rem;transform:translateZ(26px)}\r\n.rcard p{font-size:.82rem;line-height:2.1;color:var(--dim);letter-spacing:.06em;transform:translateZ(16px)}\r\n.rnum{font-family:var(--mono);font-size:.6rem;letter-spacing:.4em;color:var(--iris-soft);display:block;margin-bottom:1.1rem;transform:translateZ(32px)}\r\n\r\n/* ---------- works : scroll-driven 3D spiral cards ---------- */\r\n.works{\r\n  position:relative;display:block;min-height:clamp(700px,94vh,980px);margin-top:5.2rem;\r\n  perspective:1600px;transform-style:preserve-3d;isolation:isolate;\r\n}\r\n.works::before{\r\n  content:\"\";position:absolute;left:50%;top:50%;width:min(30vw,300px);height:min(64vh,580px);\r\n  transform:translate(-50%,-50%) translateZ(-120px);border-radius:50%;\r\n  background:\r\n    radial-gradient(ellipse at 50% 50%,rgba(255,255,255,.22),rgba(127,235,255,.16) 18%,rgba(255,103,210,.09) 38%,transparent 68%);\r\n  filter:blur(24px);opacity:.45;pointer-events:none;mix-blend-mode:screen;\r\n}\r\n.works::after{\r\n  content:\"\";position:absolute;left:50%;top:50%;width:min(42vw,440px);height:min(42vw,440px);\r\n  transform:translate(-50%,-50%) rotateX(72deg) translateZ(-180px);border-radius:50%;\r\n  background:repeating-radial-gradient(circle,rgba(185,200,255,.12) 0 1px,transparent 1px 14px);\r\n  opacity:.22;filter:blur(.2px);pointer-events:none;\r\n}\r\n.wk{\r\n  position:absolute;left:50%;top:50%;width:min(48vw,560px);display:block;text-decoration:none;\r\n  animation:none;transform-style:preserve-3d;will-change:transform,opacity;\r\n  transform:\r\n    translate(-50%,-50%)\r\n    translate3d(var(--sx,0px),var(--sy,0px),var(--sz,0px))\r\n    rotateX(var(--srx,0deg)) rotateY(var(--sry,0deg)) rotateZ(var(--srz,0deg))\r\n    scale(var(--ss,1));\r\n  transition:opacity .25s ease;\r\n}\r\n.wk:nth-child(2){width:min(50vw,600px)}\r\n.wk:nth-child(3){width:min(42vw,500px)}\r\n@keyframes floaty{0%,100%{transform:translateY(0) rotate(.2deg)}50%{transform:translateY(-9px) rotate(-.4deg)}}\r\n.wk-in{\r\n  position:relative;border-radius:14px;overflow:hidden;aspect-ratio:4/3;\r\n  border:1px solid var(--line);transform-style:preserve-3d;will-change:transform;\r\n  transition:border-color .35s;box-shadow:0 22px 50px -22px rgba(0,0,0,.85);\r\n  background:#0a0f24;\r\n}\r\n.wk:hover .wk-in{border-color:rgba(255,79,163,.55)}\r\n.wk-in img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;\r\n  transition:transform .6s cubic-bezier(.2,.8,.2,1);filter:saturate(1.05)}\r\n.wk:hover .wk-in img.main{transform:scale(1.07)}\r\n.wk-in .gl-r,.wk-in .gl-b{opacity:0;pointer-events:none}\r\n.wk:hover .wk-in .gl-r{opacity:.55;animation:glr .5s steps(3) infinite;mix-blend-mode:screen;filter:hue-rotate(-40deg) saturate(3)}\r\n.wk:hover .wk-in .gl-b{opacity:.45;animation:glb .42s steps(3) infinite reverse;mix-blend-mode:screen;filter:hue-rotate(140deg) saturate(3)}\r\n@keyframes glr{0%{transform:translate(3px,0);clip-path:inset(8% 0 64% 0)}33%{transform:translate(-3px,1px);clip-path:inset(48% 0 22% 0)}66%{transform:translate(2px,-1px);clip-path:inset(75% 0 4% 0)}100%{transform:translate(3px,0);clip-path:inset(8% 0 64% 0)}}\r\n@keyframes glb{0%{transform:translate(-3px,0);clip-path:inset(60% 0 12% 0)}33%{transform:translate(3px,-1px);clip-path:inset(12% 0 70% 0)}66%{transform:translate(-2px,1px);clip-path:inset(38% 0 38% 0)}100%{transform:translate(-3px,0);clip-path:inset(60% 0 12% 0)}}\r\n.wk-in .shine{position:absolute;inset:0;z-index:3;\r\n  background:linear-gradient(115deg,transparent 35%,rgba(255,255,255,.16) 48%,transparent 60%);\r\n  transform:translateX(-130%);transition:transform .9s ease;pointer-events:none}\r\n.wk:hover .wk-in .shine{transform:translateX(130%)}\r\n.wk-in::before{content:\"\";position:absolute;inset:0;z-index:1;\r\n  background:linear-gradient(to top,rgba(4,6,14,.82),transparent 52%)}\r\n.wk .tag{position:absolute;left:1.2rem;bottom:1.1rem;z-index:4;font-size:.72rem;letter-spacing:.2em;color:#fff;transform:translateZ(34px)}\r\n.wk .tag small{display:block;font-size:.58rem;letter-spacing:.3em;color:rgba(223,230,255,.6);margin-top:.4rem}\r\n.wk .idx{position:absolute;top:1rem;right:1.1rem;z-index:4;font-family:var(--mono);\n  font-size:.58rem;letter-spacing:.3em;color:rgba(223,230,255,.55);transform:translateZ(34px)}\n\n/* ---------- art into commerce ---------- */\n#commerce{max-width:1160px}\n.commerceBox{\n  position:relative;margin-top:2.6rem;padding:clamp(1.8rem,4vw,3rem);\n  border:1px solid rgba(139,123,255,.22);border-radius:18px;overflow:hidden;\n  background:\n    radial-gradient(45% 80% at 18% 0%,rgba(139,123,255,.18),transparent 62%),\n    radial-gradient(45% 80% at 82% 100%,rgba(255,79,163,.13),transparent 64%),\n    rgba(5,8,20,.58);\n  transform-style:preserve-3d;\n}\n.commerceBox::before{\n  content:\"\";position:absolute;inset:-30%;pointer-events:none;opacity:.5;mix-blend-mode:screen;\n  background:\n    radial-gradient(circle at 25% 42%,rgba(255,255,255,.35) 0 1px,transparent 2px),\n    radial-gradient(circle at 76% 36%,rgba(151,222,255,.45) 0 1px,transparent 2px),\n    radial-gradient(circle at 50% 74%,rgba(255,151,218,.34) 0 1px,transparent 2px);\n  background-size:90px 90px,130px 130px,160px 160px;\n  animation:commerceDust 18s linear infinite;\n}\n@keyframes commerceDust{to{transform:translate3d(7%,5%,0) rotate(8deg)}}\n.commerceBox p{\n  position:relative;max-width:48em;margin:0;color:#eef4ff;font-family:var(--serif);\n  font-size:clamp(.9rem,1.35vw,1.02rem);line-height:2.35;letter-spacing:.08em;\n}\n.commerceBox p + p{margin-top:1.1rem}\n.metrics{position:relative;display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;margin-top:2rem}\n.metric{\n  position:relative;padding:1.35rem 1.2rem 1.45rem;border:1px solid rgba(139,123,255,.22);\n  border-radius:15px;background:rgba(8,12,28,.48);overflow:hidden;transform-style:preserve-3d;\n}\n.metric::after{\n  content:\"\";position:absolute;inset:-1px;opacity:0;transition:.65s;\n  background:linear-gradient(115deg,transparent 12%,rgba(255,255,255,.22),rgba(126,217,255,.18),transparent 54%);\n  transform:translateX(-85%);\n}\n.metric:hover::after{opacity:1;transform:translateX(85%)}\n.metric .label{font-family:var(--mono);font-size:.58rem;letter-spacing:.26em;color:var(--iris-soft);margin-bottom:.9rem}\n.metric .label::before{content:attr(data-no) \" / \";color:#f8fbff;letter-spacing:.18em}\n.metric .num{font-family:var(--serif);font-size:clamp(1.15rem,2.1vw,1.65rem);letter-spacing:.08em;color:#f8fbff;line-height:1.5}\n.metric .num small{font-size:.62em;color:#aeb8df;letter-spacing:.06em}\n.metric .arrow{color:#8ddcff;text-shadow:0 0 16px rgba(91,193,255,.55);margin:0 .25em}\n.commerceNote{\n  margin-top:1.15rem;font-size:.68rem;line-height:2;color:#c0c8e6;letter-spacing:.06em;\n}\n.featuredCase{\n  position:relative;margin-top:2.1rem;padding:1.55rem 1.45rem 1.65rem;border-radius:16px;\n  border:1px solid rgba(126,217,255,.2);\n  background:\n    linear-gradient(135deg,rgba(126,217,255,.1),rgba(255,79,163,.08) 48%,rgba(8,12,28,.46)),\n    rgba(8,12,28,.38);\n  overflow:hidden;\n}\n.featuredCase::before{\n  content:\"\";position:absolute;inset:0;opacity:.55;pointer-events:none;\n  background:linear-gradient(110deg,transparent 5%,rgba(255,255,255,.12),transparent 36%);\n  transform:translateX(-90%);transition:transform 1.1s cubic-bezier(.16,1,.3,1);\n}\n.rv.in .featuredCase::before{transform:translateX(120%);transition-delay:.65s}\n.commerceBox:hover .featuredCase::before{transform:translateX(120%)}\n.caseLabel{font-family:var(--mono);font-size:.57rem;letter-spacing:.34em;color:#8ddcff;margin-bottom:.7rem}\n.featuredCase h4{\n  position:relative;font-family:var(--serif);font-weight:500;color:#f8fbff;\n  font-size:clamp(1.05rem,1.8vw,1.34rem);letter-spacing:.1em;line-height:1.8;margin-bottom:.85rem;\n}\n.featuredCase p{\n  font-size:.82rem;line-height:2.15;letter-spacing:.06em;color:#dfe7ff;max-width:62em;\n}\n.caseTags{position:relative;display:flex;flex-wrap:wrap;gap:.55rem;margin-top:1rem}\n.caseTags span{\n  font-family:var(--mono);font-size:.55rem;letter-spacing:.16em;color:#e6ecff;\n  border:1px solid rgba(139,123,255,.24);border-radius:999px;padding:.45rem .65rem;\n  background:rgba(5,8,20,.28);\n}\n.caseStats{position:relative;display:grid;grid-template-columns:repeat(4,1fr);gap:.75rem;margin-top:1.2rem}\n.caseStat{\n  border:1px solid rgba(139,123,255,.18);border-radius:12px;padding:1rem .85rem;\n  background:rgba(3,6,16,.34);\n  transform:translateZ(0);\n}\n.caseStat b{display:block;font-family:var(--serif);font-size:1.15rem;color:#fff;letter-spacing:.06em;margin-bottom:.35rem}\n.caseStat span{display:block;font-family:var(--mono);font-size:.52rem;letter-spacing:.2em;color:#c0c8e6;line-height:1.7}\n.caseLink{\n  position:relative;display:inline-block;margin-top:1.05rem;font-family:var(--mono);font-size:.58rem;\n  letter-spacing:.24em;color:#f8fbff;text-decoration:underline;text-decoration-thickness:1px;text-underline-offset:.55em;\n}\n.caseLink::after{content:\"\";display:block;height:1px;margin-top:.55rem;background:linear-gradient(90deg,#ff7bc1,transparent)}\n\n/* ---------- members ---------- */\n.members{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:1.1rem;margin-top:3rem;perspective:1100px}\n.mb{border:1px solid var(--line);border-radius:14px;padding:1.9rem 1.4rem;text-align:center;\r\n  background:rgba(10,15,36,.4);transform-style:preserve-3d;will-change:transform;transition:border-color .4s}\r\n.mb:hover{border-color:rgba(139,123,255,.5)}\r\n.mb .avatar{width:74px;height:74px;margin:0 auto 1.1rem;border-radius:50%;\r\n  background:conic-gradient(from 210deg,#8b7bff,#ff4fa3,#ffd166,#4fd1ff,#8b7bff);\r\n  padding:2px;transform:translateZ(30px)}\r\n.mb:hover .avatar{filter:none}\r\n@keyframes avSpin{to{filter:hue-rotate(360deg)}}\r\n.mb .avatar img,.mb .avatar i{display:block;width:100%;height:100%;border-radius:50%;object-fit:cover;background:#f6f3ef;filter:none!important}\r\n.mb .avatar i{font-style:normal;font-family:var(--serif);font-size:1.25rem;color:var(--moon);\r\n  display:flex;align-items:center;justify-content:center}\r\n.mb h4{font-family:var(--serif);font-weight:500;font-size:.98rem;letter-spacing:.1em;margin-bottom:.5rem;transform:translateZ(20px)}\r\n.mb p{font-size:.68rem;letter-spacing:.14em;color:var(--dim);line-height:1.8;transform:translateZ(12px)}\r\n.mb.rep{grid-column:1/-1;display:grid;grid-template-columns:auto 1fr;gap:1.8rem;text-align:left;align-items:center;padding:2.2rem}\n.mb.rep .avatar{width:104px;height:104px;margin:0}\n.mb.rep > div:not(.avatar){min-width:0;max-width:100%}\n.mb.rep .role{color:#ffd9ee;font-size:.62rem;letter-spacing:.34em;margin-bottom:.5rem;font-family:var(--mono);\n  text-shadow:0 0 12px rgba(255,79,163,.42),0 1px 12px rgba(0,0,0,.75)}\r\n.mb.rep h4{font-size:1.3rem}\r\n.mb.rep p{font-size:.78rem;line-height:2.1;letter-spacing:.06em;margin-top:.7rem}\r\n@media(max-width:560px){.mb.rep{grid-template-columns:1fr;text-align:center}.mb.rep .avatar{margin:0 auto}}\r\n\r\n/* ---------- media ---------- */\r\n.mediaRow{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1.2rem;margin-top:3rem;perspective:1100px}\r\n.md{border:1px solid var(--line);border-radius:14px;padding:2rem 1.8rem;text-decoration:none;color:var(--moon);\r\n  display:block;background:rgba(10,15,36,.4);transform-style:preserve-3d;will-change:transform;transition:border-color .4s}\r\n.md:hover{border-color:rgba(255,79,163,.45)}\r\n.md .k{font-family:var(--mono);font-size:.6rem;letter-spacing:.42em;color:var(--iris-soft);margin-bottom:1rem;display:block;transform:translateZ(26px)}\r\n.md h4{font-family:var(--serif);font-weight:500;letter-spacing:.1em;margin-bottom:.8rem;transform:translateZ(20px)}\r\n.md p{font-size:.78rem;line-height:2;color:var(--dim);letter-spacing:.05em;transform:translateZ(12px)}\r\n.md .go{display:inline-block;margin-top:1.2rem;font-size:.64rem;letter-spacing:.3em;color:#fff;transform:translateZ(26px);\n  text-decoration:underline;text-decoration-thickness:1px;text-underline-offset:.45em;\n  text-shadow:0 0 12px rgba(255,79,163,.45),0 1px 12px rgba(0,0,0,.82);transition:letter-spacing .35s}\n.md:hover .go{letter-spacing:.42em}\r\n\r\n/* ---------- blog ---------- */\r\n.blogs{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:1.2rem;margin-top:3rem;perspective:1100px}\r\n.bg-card{border:1px solid var(--line);border-radius:14px;overflow:hidden;text-decoration:none;color:var(--moon);\r\n  display:block;background:rgba(10,15,36,.4);transform-style:preserve-3d;will-change:transform;transition:border-color .4s}\r\n.bg-card:hover{border-color:rgba(139,123,255,.5)}\r\n.bg-card .th{height:120px;position:relative;overflow:hidden}\r\n.bg-card .th::after{content:\"\";position:absolute;inset:0;\r\n  background:linear-gradient(115deg,transparent 30%,rgba(255,255,255,.1) 50%,transparent 70%);\r\n  transform:translateX(-130%);transition:transform .9s}\r\n.bg-card:hover .th::after{transform:translateX(130%)}\r\n.bg-card:nth-child(1) .th{background:radial-gradient(120% 130% at 20% 0%,rgba(139,123,255,.4),transparent 60%),radial-gradient(100% 100% at 90% 100%,rgba(255,79,163,.3),transparent),#0a0f24}\r\n.bg-card:nth-child(2) .th{background:radial-gradient(120% 130% at 80% 0%,rgba(255,79,163,.35),transparent 60%),radial-gradient(100% 100% at 10% 100%,rgba(79,209,255,.3),transparent),#0a0f24}\r\n.bg-card:nth-child(3) .th{background:radial-gradient(120% 130% at 50% 0%,rgba(255,209,102,.28),transparent 60%),radial-gradient(100% 100% at 90% 100%,rgba(139,123,255,.35),transparent),#0a0f24}\r\n.bg-card .bd{padding:1.5rem 1.4rem 1.7rem}\r\n.bg-card h4{font-size:.88rem;line-height:1.9;letter-spacing:.06em;font-weight:500;margin-bottom:.8rem;transform:translateZ(18px)}\r\n.bg-card time{font-family:var(--mono);font-size:.62rem;letter-spacing:.24em;color:var(--dim)}\r\n.moreLink{display:inline-block;margin-top:2.6rem;font-size:.66rem;letter-spacing:.34em;color:var(--moon);\n  text-decoration:none;border-bottom:1px solid rgba(248,251,255,.5);padding-bottom:.5rem;transition:.3s}\n.moreLink:hover{color:var(--iris-soft);border-color:var(--iris);letter-spacing:.44em;\r\n  animation:bloomTxt 1s ease-out both}\r\n@keyframes bloomTxt{\r\n  0%{filter:blur(0);text-shadow:none}\r\n  35%{filter:blur(1.6px);text-shadow:0 0 18px rgba(139,123,255,.9),0 0 36px rgba(255,79,163,.5)}\r\n  100%{filter:blur(0);text-shadow:0 0 10px rgba(139,123,255,.4)}\r\n}\r\n.md:hover .go,.wk:hover .tag,.mb:hover h4,.bg-card:hover h4{animation:bloomTxt 1s ease-out both}\r\n\r\n/* ---------- contact ---------- */\r\n#contact{text-align:center;padding-bottom:9rem}\r\n#contact h3{margin-bottom:2.4rem}\r\n.cta{display:inline-block;text-decoration:none;font-size:.78rem;letter-spacing:.42em;text-indent:.42em;color:#fff;\r\n  padding:1.25rem 3.6rem;border-radius:999px;position:relative;border:1px solid rgba(139,123,255,.55);\r\n  background:linear-gradient(120deg,rgba(139,123,255,.18),rgba(255,79,163,.16));\r\n  transition:box-shadow .45s,border-color .45s;overflow:hidden;will-change:transform}\r\n.cta:hover{box-shadow:0 0 46px rgba(139,123,255,.4),0 0 80px rgba(255,79,163,.18);border-color:var(--pink);\r\n  animation:bloomTxt 1s ease-out both}\r\n.cta::after{content:\"\";position:absolute;inset:0;\r\n  background:linear-gradient(115deg,transparent 35%,rgba(255,255,255,.2) 50%,transparent 65%);\r\n  transform:translateX(-130%);transition:transform .9s}\r\n.cta:hover::after{transform:translateX(130%)}\r\n\r\n/* ---------- footer ---------- */\r\nfooter{border-top:1px solid var(--line);padding:4.5rem clamp(1.4rem,5vw,3rem) 3.5rem;\r\n  position:relative;z-index:5;background:rgba(3,4,11,.92)}\r\n.viviris-custom-element-root.wix-oversize footer::after{content:\"\";position:absolute;left:0;right:0;top:100%;height:var(--viviris-extra-height,0px);background:rgba(3,4,11,.92);pointer-events:none}\r\n.ft{max-width:1080px;margin:0 auto;display:grid;grid-template-columns:1fr auto;gap:3rem}\r\n.ft .mark{font-family:var(--serif);letter-spacing:.2em;font-size:1.1rem;margin-bottom:1.4rem}\r\n.ft dl{font-size:.72rem;line-height:2.2;color:var(--dim);letter-spacing:.06em}\r\n.ft dt{float:left;clear:left;width:7.5em;color:#c0c8e6}\n.ft .sns{display:flex;gap:1.4rem;flex-wrap:wrap}\r\n.ft .sns a{color:var(--dim);text-decoration:underline;text-decoration-thickness:1px;text-underline-offset:.45em;font-size:.66rem;letter-spacing:.26em;transition:.3s}\n.ft .sns a:hover{color:var(--pink)}\r\n.ft .legal{margin-top:2.4rem;display:flex;gap:1.6rem;flex-wrap:wrap}\r\n.ft .legal a{color:#b7c1e4;font-size:.62rem;letter-spacing:.14em;text-decoration:underline;text-decoration-thickness:1px;text-underline-offset:.4em}\n.ft .legal a:hover{color:var(--dim)}\r\n.copyright{max-width:1080px;margin:3rem auto 0;font-size:.6rem;letter-spacing:.22em;color:#454e6e}\r\n@media(max-width:720px){.ft{grid-template-columns:1fr}}\r\n\r\n.rv{opacity:0;transform:translateY(34px);transition:opacity 1s ease,transform 1s ease}\r\n.rv.in{opacity:1;transform:none}\r\n.cards3 .rcard,.members .mb,.mediaRow .md,.blogs .bg-card,.commerceBox,.metrics .metric{\n  opacity:0;\r\n  transform:translateY(34px) scale(.985);\r\n  filter:blur(16px);\r\n  transition:\r\n    opacity 1.45s cubic-bezier(.16,1,.3,1),\r\n    transform 1.45s cubic-bezier(.16,1,.3,1),\r\n    filter 1.45s cubic-bezier(.16,1,.3,1),\r\n    border-color .4s;\r\n}\r\n.rv.in .cards3 .rcard,.rv.in .members .mb,.rv.in .mediaRow .md,.rv.in .blogs .bg-card,.rv.in .commerceBox,.rv.in .metrics .metric{\n  opacity:1;\r\n  transform:none;\r\n  filter:blur(0);\r\n}\r\n.rv.in .cards3 .rcard:nth-child(2),\n.rv.in .members .mb:nth-child(2),\n.rv.in .mediaRow .md:nth-child(2),\n.rv.in .blogs .bg-card:nth-child(2),\n.rv.in .metrics .metric:nth-child(2){transition-delay:.12s}\n.rv.in .cards3 .rcard:nth-child(3),\n.rv.in .members .mb:nth-child(3),\n.rv.in .mediaRow .md:nth-child(3),\n.rv.in .blogs .bg-card:nth-child(3),\n.rv.in .metrics .metric:nth-child(3){transition-delay:.24s}\n.rv.in .members .mb:nth-child(4),\r\n.rv.in .blogs .bg-card:nth-child(4){transition-delay:.36s}\r\n.rv.in .members .mb:nth-child(5){transition-delay:.48s}\r\n\r\n@media(max-width:760px){\r\n  html,body{width:100%;max-width:100%;overflow-x:hidden}\r\n  .corner{display:none}\r\n  #welcome{padding:0 1.15rem;gap:1.65rem}\r\n  .w-mark{\r\n    font-size:clamp(1.86rem,9.2vw,2.35rem);\r\n    letter-spacing:.08em;text-indent:.08em;white-space:nowrap;max-width:100%;\r\n  }\r\n  .w-sub{font-size:.78rem;letter-spacing:.16em;line-height:1.9;max-width:17.5rem}\r\n  .w-sub .en{font-size:.52rem;letter-spacing:.28em;text-indent:.28em}\r\n  #enterBtn{width:min(76vw,286px);padding:.92rem 1.45rem;font-size:.7rem}\r\n  .w-note{font-size:.58rem;line-height:1.9;letter-spacing:.16em;padding:0 1rem}\r\n  .w-ring{width:min(82vmin,330px);height:min(82vmin,330px)}\r\n\r\n  #brand{top:1rem;left:1rem;font-size:.72rem;letter-spacing:.16em;max-width:48vw;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\r\n  #soundBtn{top:.9rem;right:.85rem;padding:.48rem .82rem;font-size:.56rem;letter-spacing:.24em;text-indent:.24em}\r\n  #chapNav{\r\n    left:50%;top:auto;bottom:.95rem;transform:translateX(-50%);\r\n    flex-direction:row;gap:.92rem;padding:.65rem .8rem;border-radius:999px;\r\n    background:rgba(4,6,14,.42);border:1px solid rgba(185,200,255,.12);\r\n    backdrop-filter:blur(10px);-webkit-backdrop-filter:blur(10px)\r\n  }\r\n  .cn{gap:0}\r\n  .cn b{width:5px;height:5px}\r\n  .cn span{display:none}\r\n  #scrollHint{bottom:4.8rem;font-size:.6rem}\r\n  .cap .tate{display:none}\r\n  .cap-in{max-width:min(340px,calc(100vw - 2.4rem));padding:1.35rem 1.08rem;border-radius:15px}\r\n  .cap .ch-no{font-size:.5rem;letter-spacing:.28em;margin-bottom:.85rem}\r\n  .cap h2{font-size:clamp(.98rem,5vw,1.28rem);line-height:1.68;letter-spacing:.045em;margin-bottom:1rem}\r\n  .cap p{font-size:.74rem;line-height:2;letter-spacing:.025em}\r\n  #hud{display:none}\r\n  #philosophy .ghost{display:none}\r\n  #landing{padding-top:10vh}\r\n  .sec{max-width:100%;padding:4.6rem 1.15rem;perspective:none}\r\n  .sec#works{padding-top:6rem;padding-bottom:6rem}\r\n  .eyebrow{font-size:.55rem;letter-spacing:.38em;margin-bottom:1rem}\r\n  .rv.in .eyebrow{letter-spacing:.28em}\r\n  .sec h3{font-size:clamp(1.12rem,6vw,1.48rem);line-height:1.72;letter-spacing:.055em;margin-bottom:1.1rem}\r\n  .sec .lead{font-size:.8rem;line-height:1.95;letter-spacing:.035em}\r\n  .cards3,.members,.mediaRow,.blogs,.metrics{grid-template-columns:1fr;gap:1rem;margin-top:2rem;perspective:none}\n  .cards3,.members,.mediaRow,.blogs,.metrics,\n  .rcard,.md,.bg-card,.mb,.commerceBox,.metric{min-width:0;width:100%}\n  .rcard,.md,.bg-card,.mb,.commerceBox,.metric{border-radius:12px}\n  .rcard,.md{padding:1.65rem 1.35rem}\n  .commerceBox{padding:1.65rem 1.35rem}\n  .commerceBox p{font-size:.84rem;line-height:2.05;letter-spacing:.045em}\n  .metric{padding:1.15rem 1rem 1.25rem}\n  .metric .label{font-size:.54rem;letter-spacing:.24em}\n  .metric .num{font-size:1.12rem}\n  .featuredCase{padding:1.3rem 1.05rem 1.4rem;border-radius:13px}\n  .featuredCase p{font-size:.78rem;line-height:1.95;letter-spacing:.035em}\n  .caseTags{gap:.45rem}\n  .caseTags span{font-size:.48rem;letter-spacing:.1em;padding:.38rem .5rem}\n  .caseStats{grid-template-columns:1fr 1fr;gap:.55rem}\n  .caseStat{padding:.85rem .65rem}\n  .caseStat b{font-size:.96rem}\n  .caseStat span{font-size:.46rem;letter-spacing:.12em}\n  .caseLink{font-size:.52rem;letter-spacing:.18em}\n  .commerceNote{font-size:.62rem;line-height:1.8}\n  .mb{padding:1.55rem 1.25rem}\n  .mb.rep{padding:1.65rem 1.25rem;gap:1.1rem;justify-items:center}\n  .mb.rep > div:not(.avatar){width:100%;min-width:0}\n  .mb.rep .role,.mb.rep h4,.mb.rep p{max-width:100%;overflow-wrap:anywhere}\n  .mb.rep .avatar{width:92px;height:92px}\n  .mb.rep h4{font-size:1.08rem}\n  .mb h4 small{display:block;margin-top:.35rem;letter-spacing:.16em!important;overflow-wrap:anywhere}\n  .mb.rep p{font-size:.74rem;line-height:1.95}\n  .cap h2,.cap p,.sec h3,.sec .lead,.rcard h4,.rcard p,.md h4,.md p,.bg-card h4,.bg-card p{word-break:normal;line-break:strict;overflow-wrap:break-word}\n  .bg-card .th{height:96px}\r\n  .bg-card .bd{padding:1.25rem 1.2rem 1.45rem}\r\n  .moreLink{margin-top:2rem}\r\n  .cta{width:min(100%,320px);padding:1.08rem 1.2rem;font-size:.7rem;letter-spacing:.28em;text-indent:.28em}\r\n  .works{display:grid;grid-template-columns:1fr;gap:1.4rem;min-height:auto;perspective:none}\r\n  .works::before,.works::after{display:none}\r\n  .wk,.wk:nth-child(2),.wk:nth-child(3){\r\n    position:relative;left:auto;top:auto;width:100%;opacity:1!important;\r\n    transform:none!important;animation:floaty 7.5s ease-in-out infinite;animation-delay:var(--d,0s)\r\n  }\r\n  .wk-in{border-radius:12px;aspect-ratio:4/3}\r\n  .wk .tag{left:1rem;bottom:1rem;font-size:.66rem;letter-spacing:.16em}\r\n  .wk .tag small{font-size:.52rem;letter-spacing:.22em}\r\n  .wk .idx{top:.9rem;right:.95rem;font-size:.52rem}\r\n  footer{padding:3.6rem 1.2rem 4.4rem}\r\n  .ft{gap:2rem}\r\n}\r\n@media (prefers-reduced-motion: reduce){\r\n  *{animation:none!important;transition-duration:.01ms!important}\r\n  .st .ch{opacity:1!important;transform:none!important;filter:none!important}\r\n}\r\n";
  const BODY_HTML = "<div class=\"viviris-custom-element-root\"><a class=\"skipLink\" href=\"#landing\">本文へスキップ</a>\n\n<canvas id=\"gl\" aria-hidden=\"true\" role=\"presentation\"></canvas>\n<canvas id=\"petals\" aria-hidden=\"true\" role=\"presentation\" style=\"position:fixed;inset:0;width:100%;height:100%;z-index:7;pointer-events:none\"></canvas>\n\n<div class=\"corner tl\" aria-hidden=\"true\"></div><div class=\"corner tr\" aria-hidden=\"true\"></div>\n<div class=\"corner bl\" aria-hidden=\"true\"></div><div class=\"corner br\" aria-hidden=\"true\"></div>\n<div id=\"hud\" aria-hidden=\"true\">\n  <div><b>VIVIRIS_OS</b> v2.0 <span class=\"blink\">●</span></div>\r\n  <div id=\"hudDepth\">DEPTH&nbsp;-1800m</div>\r\n  <div id=\"hudChap\">CH.01 / 深海</div>\r\n</div>\r\n\r\n<div id=\"welcome\" role=\"dialog\" aria-modal=\"true\" aria-labelledby=\"welcomeTitle\" aria-describedby=\"welcomeNote\">\n  <div class=\"w-ring\" aria-hidden=\"true\"></div>\n  <h1 class=\"w-mark\" id=\"welcomeTitle\">Viviris <em>&amp;</em> Co.</h1>\n  <div class=\"w-sub\"><span class=\"en\">TOTAL CREATIVE PRODUCTION</span>深海から鮮やかな未来へ ─</div>\n  <button id=\"enterBtn\" type=\"button\" aria-label=\"サイトに入る\">E N T E R</button>\n  <div class=\"w-note\" id=\"welcomeNote\">SOUND ON ── 音楽と共にお楽しみください</div>\n</div>\n\n<a id=\"brand\" href=\"https://www.viviris-official.com/\">Viviris &amp; Co.</a>\n<button id=\"soundBtn\" class=\"on\" type=\"button\" aria-label=\"BGMを停止する\" aria-pressed=\"true\">\n  <span class=\"eq\" aria-hidden=\"true\"><i></i><i></i><i></i></span>SOUND\n</button>\n\n<nav id=\"chapNav\" aria-label=\"章ナビゲーション\">\n  <button class=\"cn act\" type=\"button\" data-go=\"0\" aria-label=\"第1章 深海へ移動\" aria-current=\"true\"><b aria-hidden=\"true\"></b><span>深海</span></button>\n  <button class=\"cn\" type=\"button\" data-go=\"1\" aria-label=\"第2章 灯火へ移動\"><b aria-hidden=\"true\"></b><span>灯火</span></button>\n  <button class=\"cn\" type=\"button\" data-go=\"2\" aria-label=\"第3章 土星へ移動\"><b aria-hidden=\"true\"></b><span>土星</span></button>\n  <button class=\"cn\" type=\"button\" data-go=\"3\" aria-label=\"第4章 開花へ移動\"><b aria-hidden=\"true\"></b><span>開花</span></button>\n  <button class=\"cn\" type=\"button\" data-go=\"4\" aria-label=\"第5章 共創へ移動\"><b aria-hidden=\"true\"></b><span>共創</span></button>\n</nav>\n\n<div id=\"scrollHint\" aria-hidden=\"true\">SCROLL</div>\n\r\n<div class=\"cap\" id=\"cap1\">\r\n  <div class=\"cap-in\">\r\n    <div class=\"ch-no\">CHAPTER 01 ── 深海</div>\r\n    <h2>未来が見えない暗闇の底で、<br>息を潜めていた。</h2>\r\n    <p>傷つくことを恐れ、なにも持たず、ただ必死に夜をやり過ごす日々。<br>\r\n    どう表現すればいいか分からない。頑張っているのに、誰にも選ばれない。<br><br>\r\n    でも、どんなに深い過酷な闇の奥底にも、<br>消えない想いが、静かに眠っている。</p>\r\n  </div>\r\n  <div class=\"tate\">深海 ── 暗闇と胎動</div>\r\n</div>\r\n\r\n<div class=\"cap\" id=\"cap2\">\r\n  <div class=\"cap-in\">\r\n    <div class=\"ch-no\">CHAPTER 02 ── 灯火</div>\r\n    <h2>なにもなかった私に、<br>生きる力をくれたのは、<br>クリエイティブだった。</h2>\r\n    <p>表現する喜びを知り、伝える手段を持ったとき、<br>私の人生は、世界を変える力を宿した。<br><br>\r\n    すべての始まりは、ひとつの想いから。<br>\r\n    私たちは、その想いを深く理解し、暗闇に小さな光を灯すパートナー。<br>\r\n    ブランド設計、Webサイト、映像、SNS発信まで。<br>\r\n    感性を生かした表現力と、成果へ導く戦略性で、<br>\r\n    まだ選ばれていない価値を、届く形へ変えていく。</p>\r\n  </div>\r\n  <div class=\"tate\">灯火 ── 覚醒</div>\r\n</div>\r\n\r\n<div class=\"cap\" id=\"cap3\">\r\n  <div class=\"cap-in\">\r\n    <div class=\"ch-no\">CHAPTER 03 ── 土星</div>\r\n    <h2>私たちはブランド・Web・映像・発信を<br>一つの世界観へ紡ぎ回転させていくチームです。</h2>\r\n    <p>土星のように、強力な遠心力で周囲を巻き込み、<br>\r\n    誰かの「叶えたい」を叶えるために、いつもその中心で回り続ける。<br><br>\r\n    凝縮されたあなたの想いは、ブランドの軸となり、<br>\r\n    Webやコンテンツを通して、人の心を動かすエネルギーへと変わる。<br>\r\n    関わるすべての人の人生を豊かにするために、私たちは今日も、共に創り続ける。</p>\r\n  </div>\r\n  <div class=\"tate\">土星 ── 共創の遠心力</div>\r\n</div>\r\n\r\n<div class=\"cap\" id=\"cap4\">\r\n  <div class=\"cap-in\">\r\n    <div class=\"ch-no\">CHAPTER 04 ── 生命の開花と上昇</div>\r\n    <h2>どんな過酷な環境にあっても、<br>人は<em>何度だって再出発できる</em>。</h2>\r\n    <p>光を灯された想いは、いま鮮やかな生命を宿す。<br>\r\n    虹色に輝く花々が開くように、<br>\r\n    あなたのビジネスが、まだ見ぬ未来へと咲き誇っていく。<br><br>\r\n    想いは形になり、形は選ばれる理由になる。</p>\r\n  </div>\r\n  <div class=\"tate\">開花 ── 再出発のきっかけ</div>\r\n</div>\r\n\r\n<div id=\"story\" aria-hidden=\"true\"></div>\r\n\r\n<main id=\"landing\" tabindex=\"-1\">\n\r\n  <section class=\"sec rv\" id=\"vow\">\r\n    <div class=\"eyebrow\">CHAPTER 05 ── 共創と日常</div>\r\n    <h3 class=\"st\">灯した光を、<span class=\"spark\">絶やさないために</span>。</h3>\r\n    <p class=\"lead fd\">\r\n      私たちは、ブランド設計・Web制作・映像・SNS発信を通して、<br>\r\n      あなたの商品やサービスに宿る魅力を、選ばれる体験へ育てます。<br><br>\r\n      作って終わりではなく、公開後の発信・改善・運用まで。<br>\r\n      日常のクリエイティブに、知性と戦略を注ぎ込み続けます。\r\n    </p>\r\n  </section>\r\n\r\n  <div class=\"rule\"></div>\r\n\r\n  <section class=\"sec rv\" id=\"philosophy\">\r\n    <div class=\"ghost\" id=\"ghostTxt\">理念</div>\r\n    <div class=\"orbit\"></div>\r\n    <div class=\"eyebrow\">PHILOSOPHY ── 理念</div>\r\n    <blockquote class=\"st\">\r\n      <b>理念</b>から逆算するデザイン理論で、事業者の<strong>ブランディング</strong>を強化し、<br>\r\n      事業スケールを<span class=\"x10\" id=\"x10\">10倍</span>にする<b>「ブランドOS」</b>を構築したクリエイティブを届ける。\r\n    </blockquote>\r\n  </section>\r\n\r\n  <div class=\"marquee\" aria-hidden=\"true\">\r\n    <div class=\"mq-track\">\r\n      <span>想いは形になり、形は価値を生む ── <em>VIVIRIS &amp; CO.</em> ──&nbsp;</span>\r\n      <span>深海から鮮やかな未来へ ── <em>FROM ABYSS TO VIVID FUTURE</em> ──&nbsp;</span>\r\n      <span>想いは形になり、形は価値を生む ── <em>VIVIRIS &amp; CO.</em> ──&nbsp;</span>\r\n      <span>深海から鮮やかな未来へ ── <em>FROM ABYSS TO VIVID FUTURE</em> ──&nbsp;</span>\r\n    </div>\r\n  </div>\r\n\r\n  <section class=\"sec rv\" id=\"reasons\">\r\n    <div class=\"eyebrow\">WHY VIVIRIS ── 選ばれる理由</div>\r\n    <h3 class=\"st\">世界観をつくり、成果まで伴走する<br>クリエイティブチームです。</h3>\r\n    <p class=\"lead fd\">ブランドの核を見つけ、Web・映像・発信へ展開し、公開後の成長まで支えます。</p>\r\n    <div class=\"cards3 tiltGroup\">\r\n      <div class=\"rcard\" data-tilt>\r\n        <span class=\"rnum\">01 / VISION</span>\r\n        <h4>ビジョンを言語化</h4>\r\n        <p>言葉にならない想いを整理し、ブランドの軸と世界観へ落とし込みます。</p>\r\n      </div>\r\n      <div class=\"rcard\" data-tilt>\r\n        <span class=\"rnum\">02 / STRATEGY</span>\r\n        <h4>選ばれる導線設計</h4>\r\n        <p>見た目の美しさだけでなく、伝わる順番・導線・行動まで設計します。</p>\r\n      </div>\r\n      <div class=\"rcard\" data-tilt>\r\n        <span class=\"rnum\">03 / PARTNERSHIP</span>\r\n        <h4>公開後も育てる伴走力</h4>\r\n        <p>企画から制作、発信、運用改善まで、事業の成長に合わせて支えます。</p>\r\n      </div>\r\n    </div>\r\n  </section>\r\n\r\n  <div class=\"rule\"></div>\r\n\r\n  <section class=\"sec rv\" id=\"works\">\r\n    <div class=\"eyebrow\">WORKS ── 共に創り上げたクリエイティブ</div>\r\n    <h3 class=\"st\">クライアントの想いを受け取り、<br>一緒に描いてきたクリエイティブ。</h3>\r\n    <div class=\"works tiltGroup\">\r\n      <a class=\"wk\" style=\"--d:0s\" href=\"https://www.viviris-official.com/works-1\" target=\"_blank\" rel=\"noopener\" data-tilt data-tilt-max=\"12\">\r\n        <div class=\"wk-in\">\r\n          <img class=\"main\" src=\"https://static.wixstatic.com/media/263763_b45a8326d44b4bf391701a1e42c3c5ef~mv2.webp\" alt=\"nitoro HAIR SALON\" loading=\"lazy\" decoding=\"async\" width=\"1280\" height=\"956\">\n          <img class=\"gl-r\" alt=\"\" aria-hidden=\"true\"><img class=\"gl-b\" alt=\"\" aria-hidden=\"true\">\r\n          <div class=\"shine\"></div>\r\n          <span class=\"idx\">PRJ_001</span>\r\n          <div class=\"tag\">NITORO HAIR SALON<small>WEB DESIGN</small></div>\r\n        </div>\r\n      </a>\r\n      <a class=\"wk\" style=\"--d:-2.4s\" href=\"https://www.viviris-official.com/works-1\" target=\"_blank\" rel=\"noopener\" data-tilt data-tilt-max=\"12\">\r\n        <div class=\"wk-in\">\r\n          <img class=\"main\" src=\"https://static.wixstatic.com/media/263763_0c646686215e4608a6c531598236bf6d~mv2.webp\" alt=\"ROUGE CACAO\" loading=\"lazy\" decoding=\"async\" width=\"1280\" height=\"720\">\n          <img class=\"gl-r\" alt=\"\" aria-hidden=\"true\"><img class=\"gl-b\" alt=\"\" aria-hidden=\"true\">\r\n          <div class=\"shine\"></div>\r\n          <span class=\"idx\">PRJ_002</span>\r\n          <div class=\"tag\">ROUGE CACAO<small>BRAND SITE</small></div>\r\n        </div>\r\n      </a>\r\n      <a class=\"wk\" style=\"--d:-4.8s\" href=\"https://www.viviris-official.com/works-1\" target=\"_blank\" rel=\"noopener\" data-tilt data-tilt-max=\"12\">\r\n        <div class=\"wk-in\">\r\n          <img class=\"main\" src=\"https://static.wixstatic.com/media/263763_5686629877aa4b5bb95564c85a20ac30~mv2.webp\" alt=\"HIKARI DINING TOKYO\" loading=\"lazy\" decoding=\"async\" width=\"1280\" height=\"933\">\n          <img class=\"gl-r\" alt=\"\" aria-hidden=\"true\"><img class=\"gl-b\" alt=\"\" aria-hidden=\"true\">\r\n          <div class=\"shine\"></div>\r\n          <span class=\"idx\">PRJ_003</span>\r\n          <div class=\"tag\">HIKARI DINING TOKYO<small>RESTAURANT SITE</small></div>\r\n        </div>\r\n      </a>\r\n    </div>\r\n    <a class=\"moreLink\" href=\"https://www.viviris-official.com/works-1\" target=\"_blank\" rel=\"noopener\">VIEW ALL WORKS →</a>\r\n  </section>\n\n  <div class=\"rule\"></div>\n\n  <section class=\"sec rv\" id=\"commerce\">\n    <div class=\"eyebrow\">ART INTO COMMERCE ── アートを、商業価値へ。</div>\n    <h3 class=\"st\">美しいだけで終わらせない。<br>感性を、選ばれる理由へ変えていく。</h3>\n    <div class=\"commerceBox\">\n      <p>Viviris &amp; Co.がつくるのは、ただ美しいだけのデザインではありません。</p>\n      <p>感性、物語、世界観を、伝わる導線・高単価でも納得される体験・成約へつながるブランド構造へ翻訳していく。</p>\n      <p>アートの熱量を、商業の成果へ昇華させる。それが私たちのブランディングです。</p>\n      <div class=\"metrics\">\n        <div class=\"metric\">\n          <div class=\"label\" data-no=\"01\">PRICE VALUE</div>\n          <div class=\"num\">900円 <span class=\"arrow\">→</span> 1,400円<small> 客単価</small></div>\n        </div>\n        <div class=\"metric\">\n          <div class=\"label\" data-no=\"02\">REPEAT</div>\n          <div class=\"num\">45% <span class=\"arrow\">→</span> 70%<small> リピート率</small></div>\n        </div>\n        <div class=\"metric\">\n          <div class=\"label\" data-no=\"03\">ORDER VALUE</div>\n          <div class=\"num\">5〜10万 <span class=\"arrow\">→</span> 30万円〜<small> 平均受注単価</small></div>\n        </div>\n      </div>\n      <div class=\"featuredCase\">\n        <div class=\"caseLabel\">FEATURED CASE</div>\n        <h4>AIアートイベント「扉展」</h4>\n        <p>SNSフォロワー5万人規模のAIクリエイターによる複合型AIアートフェスにて、ブランドページ、予約導線、メタバースワールド、協賛提案、クーポン施策、出展者対応、運営体制までを一貫支援。</p>\n        <p>リスティング広告に頼らず、世界観設計とインフルエンサー起点の信頼導線、シンプルな決済導線を組み合わせ、有料開催でも高い行動転換を記録しました。</p>\n        <div class=\"caseTags\">\n          <span>BRAND STRATEGY</span>\n          <span>EVENT BUSINESS DESIGN</span>\n          <span>WEB / CV FLOW</span>\n          <span>METAVERSE EXPERIENCE</span>\n          <span>SPONSOR PROPOSAL</span>\n          <span>PROJECT MANAGEMENT</span>\n        </div>\n        <div class=\"caseStats\">\n          <div class=\"caseStat\"><b>1,757</b><span>UNIQUE VISITORS</span></div>\n          <div class=\"caseStat\"><b>5%</b><span>CVR / PAID EVENT</span></div>\n          <div class=\"caseStat\"><b>6:06</b><span>AVG SESSION TIME</span></div>\n          <div class=\"caseStat\"><b>900名超</b><span>ATTENDANCE / ADMIN</span></div>\n        </div>\n        <a class=\"caseLink\" href=\"https://cluster.mu/e/7557e309-5da8-4fc9-8cd1-dc82eff6d09c\" target=\"_blank\" rel=\"noopener\">CLUSTER EVENT PAGE →</a>\n      </div>\n      <div class=\"commerceNote\">※掲載数値は支援事例・レポート・管理画面記録に基づく一例です。成果は事業状況・運用体制により異なり、結果を保証するものではありません。</div>\n    </div>\n  </section>\n\n  <div class=\"rule\"></div>\n\n  <section class=\"sec rv\" id=\"member\">\n    <div class=\"eyebrow\">MEMBER ── プロジェクトを共に進める仲間たち</div>\n    <h3 class=\"st\">最適なチームを編成し、<br>あなたの目指すゴールへ伴走します。</h3>\r\n    <div class=\"members tiltGroup\">\r\n      <div class=\"mb rep\" data-tilt data-tilt-max=\"4\">\r\n        <div class=\"avatar\"><img src=\"https://static.wixstatic.com/media/c0ea98_809a78b7add44a2789a54650db79c4c6~mv2.webp\" alt=\"塙 香那\" loading=\"lazy\"></div>\r\n        <div>\r\n          <div class=\"role\">FOUNDER / 代表</div>\r\n          <h4>塙 香那 <small style=\"font-size:.6em;color:var(--dim);letter-spacing:.2em\">KANA HANAWA</small></h4>\r\n          <p>ジュエリーデザイナーとして独立後、国内外180店舗に商品を展開。Webデザイナー・ディレクター、教育事業を経て、2024年にViviris &amp; Co.へと名称を変更。戦略性とアート性を武器に、誰にも真似できない唯一無二のブランド体験を創り続けています。2026年、音楽レーベル V&amp;Co.Records を設立。</p>\r\n        </div>\r\n      </div>\r\n      <div class=\"mb\" data-tilt><div class=\"avatar\"><img src=\"https://static.wixstatic.com/media/c0ea98_f54d54f724b44b26bef4e9cece9b0330~mv2.png\" alt=\"Masaya OKUI\" loading=\"lazy\"></div><h4>Masaya OKUI</h4><p>bubble開発<br>PM</p></div>\r\n      <div class=\"mb\" data-tilt><div class=\"avatar\"><img src=\"https://static.wixstatic.com/media/c0ea98_b7dd4ee0afbb4f629746cec16775e263~mv2.png\" alt=\"Asuka KATSUTA\" loading=\"lazy\"></div><h4>Asuka KATSUTA</h4><p>LPデザイナー<br>Webデザイナー</p></div>\r\n      <div class=\"mb\" data-tilt><div class=\"avatar\"><img src=\"https://static.wixstatic.com/media/c0ea98_1204401cc2fc470c9adcec08de61ee67~mv2.png\" alt=\"Tomomi TERASHI\" loading=\"lazy\"></div><h4>Tomomi TERASHI</h4><p>デザイン<br>アシスタント</p></div>\r\n      <div class=\"mb\" data-tilt><div class=\"avatar\"><img src=\"https://static.wixstatic.com/media/c0ea98_d3366593121e41bc8f1f30f0b53417a5~mv2.png\" alt=\"Masaya HONJO\" loading=\"lazy\"></div><h4>Masaya HONJO</h4><p>Webコーダー<br>システムエンジニア</p></div>\r\n    </div>\r\n    <a class=\"moreLink\" href=\"https://www.viviris-official.com/member\" target=\"_blank\" rel=\"noopener\">MEMBER PAGE →</a>\r\n  </section>\r\n\r\n  <div class=\"rule\"></div>\r\n\r\n  <section class=\"sec rv\" id=\"media\">\r\n    <div class=\"eyebrow\">MEDIA ── 日常のクリエイティブ</div>\r\n    <h3 class=\"st\">灯した光を、日々の発信でも。</h3>\r\n    <div class=\"mediaRow tiltGroup\">\r\n      <a class=\"md\" data-tilt href=\"https://open.spotify.com/show/7AUaHj1t3dcHnxuaAUGC8H\" target=\"_blank\" rel=\"noopener\">\r\n        <span class=\"k\">PODCAST</span>\r\n        <h4>飾らない日々のおしゃべり</h4>\r\n        <p>うまくいった日も、いかなかった日も。ちょっと力を抜いて話す番組。「わかる〜」と思いながら、気軽に聴いてください。</p>\r\n        <span class=\"go\">SPOTIFYで聴く →</span>\r\n      </a>\r\n      <a class=\"md\" data-tilt href=\"https://www.youtube.com/@GalDesignerPonkana\" target=\"_blank\" rel=\"noopener\">\r\n        <span class=\"k\">YOUTUBE</span>\r\n        <h4>デザイン知識チャンネル</h4>\r\n        <p>高単価ブランディングを構築する生き方と、知って得するデザインの知識を発信しています。</p>\r\n        <span class=\"go\">チャンネルへ →</span>\r\n      </a>\r\n      <a class=\"md\" data-tilt href=\"https://www.youtube.com/@PONKANAGAME\" target=\"_blank\" rel=\"noopener\">\r\n        <span class=\"k\">GAME</span>\r\n        <h4>ゲーム実況チャンネル</h4>\r\n        <p>仕事とは違う一面も。リアルな時間を一緒に楽しめる新企画、はじまりました。</p>\r\n        <span class=\"go\">遊びに行く →</span>\r\n      </a>\r\n    </div>\r\n  </section>\r\n\r\n  <div class=\"rule\"></div>\r\n\r\n  <section class=\"sec rv\" id=\"blog\">\r\n    <div class=\"eyebrow\">BLOG ── Web制作の豆知識</div>\r\n    <h3 class=\"st\">知って得する、Web制作のヒント。</h3>\r\n    <div class=\"blogs tiltGroup\">\r\n      <a class=\"bg-card\" data-tilt href=\"https://www.viviris-official.com/post/%E8%BA%AB%E4%BD%93%E3%81%AE%E6%B0%B4%E5%88%86%E3%82%92%E5%A4%A7%E5%8D%8A%E5%A4%B1%E3%81%A3%E3%81%9F%E3%80%81%E3%81%82%E3%81%AE%E6%97%A5%E3%81%AE%E5%87%BA%E4%BC%9A%E3%81%84\" target=\"_blank\" rel=\"noopener\">\r\n        <div class=\"th\"></div>\r\n        <div class=\"bd\"><h4>身体の水分を大半失った、あの日の出会い</h4><time>STAFF STORY</time></div>\r\n      </a>\r\n      <a class=\"bg-card\" data-tilt href=\"https://www.viviris-official.com/blog\" target=\"_blank\" rel=\"noopener\">\r\n        <div class=\"th\"></div>\r\n        <div class=\"bd\"><h4>あの人が売れてるのに、あなたが売れてない理由「完全解説」</h4><time>BRANDING</time></div>\r\n      </a>\r\n      <a class=\"bg-card\" data-tilt href=\"https://www.viviris-official.com/blog\" target=\"_blank\" rel=\"noopener\">\r\n        <div class=\"th\"></div>\r\n        <div class=\"bd\"><h4>たった1つの質問で、プロジェクトが止まった話。</h4><time>BEHIND THE SCENES</time></div>\r\n      </a>\r\n    </div>\r\n    <a class=\"moreLink\" href=\"https://www.viviris-official.com/blog\" target=\"_blank\" rel=\"noopener\">ブログ一覧へ →</a>\r\n  </section>\r\n\r\n  <div class=\"rule\"></div>\r\n\r\n  <section class=\"sec rv\" id=\"contact\">\r\n    <div class=\"eyebrow\">CONTACT</div>\r\n    <h3 class=\"st\">あなたのビジョンを、次のフェーズへ。<br>さあ、共に新しい世界を描きましょう。</h3>\r\n    <p class=\"lead fd\" style=\"margin:0 auto 3rem\">まずはお気軽にご相談ください。プロジェクトのご相談・お見積もりだけでも歓迎です。</p>\r\n    <a class=\"cta\" id=\"ctaBtn\" href=\"https://www.viviris-official.com/contact\" target=\"_blank\" rel=\"noopener\">お問い合わせはこちら</a>\r\n  </section>\r\n\r\n  <footer>\r\n    <div class=\"ft\">\r\n      <div>\r\n        <div class=\"mark\">Viviris &amp; Co.</div>\r\n        <dl>\r\n          <dt>会社名</dt><dd>制作プロダクション Viviris &amp; Co.／音楽レーベル V&amp;Co.Records</dd>\r\n          <dt>所在地</dt><dd>東京都</dd>\r\n          <dt>代表者</dt><dd>塙 香那（KANA HANAWA）</dd>\r\n          <dt>設立</dt><dd>2022年10月</dd>\r\n          <dt>事業内容</dt><dd>開発事業／スクール事業／エンターテイメント事業</dd>\r\n        </dl>\r\n        <div class=\"legal\">\r\n          <a href=\"https://www.viviris-official.com/privacypolicy\" target=\"_blank\" rel=\"noopener\">Privacy Policy</a>\r\n          <a href=\"https://www.viviris-official.com/tokushoho\" target=\"_blank\" rel=\"noopener\">特定商取引法に基づく表記</a>\r\n        </div>\r\n      </div>\r\n      <div class=\"sns\">\r\n        <a href=\"https://line.me/R/ti/p/@451xlxkf\" target=\"_blank\" rel=\"noopener\">LINE</a>\r\n        <a href=\"https://www.youtube.com/@GalDesignerPonkana\" target=\"_blank\" rel=\"noopener\">YOUTUBE</a>\r\n        <a href=\"https://www.instagram.com/ponkanadesign/\" target=\"_blank\" rel=\"noopener\">INSTAGRAM</a>\r\n        <a href=\"https://x.com/galdesignerpon\" target=\"_blank\" rel=\"noopener\">X</a>\r\n      </div>\r\n    </div>\r\n    <div class=\"copyright\">© 2026 Viviris &amp; Co. All Rights Reserved.</div>\r\n  </footer>\r\n</main>\r\n\r\n<audio id=\"bgm\" loop preload=\"none\" src=\"https://static.wixstatic.com/mp3/263763_557ab11bb9d94c36855ddf52cd0c6d02.mp3\"></audio></div>";
  const APP_SCRIPT = "(function(){\r\n\"use strict\";\r\nconst reduced = matchMedia(\"(prefers-reduced-motion: reduce)\").matches;\nconst mobile  = innerWidth < 760;\nconst hw = navigator.hardwareConcurrency || 8;\nconst mem = navigator.deviceMemory || 8;\nconst lowPower = reduced || mobile || hw <= 4 || mem <= 4;\n\r\n/* ---------- renderer / scene ---------- */\r\nconst canvas = document.getElementById(\"gl\");\nconst renderer = new THREE.WebGLRenderer({canvas, antialias:!mobile, alpha:false});\nconst DPR_CAP = reduced ? 1 : (mobile ? 1.12 : (lowPower ? 1.3 : 1.5));\nrenderer.setPixelRatio(Math.min(devicePixelRatio || 1, DPR_CAP));\nrenderer.setSize(innerWidth, innerHeight);\r\n\r\nconst scene = new THREE.Scene();\r\nconst COL = {\r\n  abyss : new THREE.Color(0x04060e),\r\n  deep  : new THREE.Color(0x071226),\r\n  nebula: new THREE.Color(0x140a2e)\r\n};\r\nscene.fog = new THREE.FogExp2(0x04060e, 0.028);\r\n\r\nconst camera = new THREE.PerspectiveCamera(55, innerWidth/innerHeight, .1, 300);\r\ncamera.position.set(0, 0, 26);\r\n\r\nconst amb = new THREE.AmbientLight(0x223055, .55); scene.add(amb);\r\nconst core= new THREE.PointLight(0x8b7bff, 0, 90); scene.add(core);\r\nconst pinkL=new THREE.PointLight(0xff4fa3, 0, 70); pinkL.position.set(8,6,8); scene.add(pinkL);\r\n\r\n/* ---------- GLSL helpers are inlined per-material ---------- */\r\n\r\n/* ============================================================\r\n   Background: 4 photographic environments, scroll-crossfaded\r\n   bg1 深海の底 → bg2 光射す海中 → bg3 虹色の花園 → bg4 未来への小道\r\n   ============================================================ */\r\nfunction loadTex(dataUri){\r\n  const tx=new THREE.TextureLoader().load(dataUri);\r\n  tx.minFilter=THREE.LinearFilter; tx.magFilter=THREE.LinearFilter;\r\n  tx.generateMipmaps=false; tx.wrapS=tx.wrapT=THREE.ClampToEdgeWrapping;\r\n  return tx;\r\n}\r\nconst BG1=\"data:image/webp;base64,\";\r\nconst BG2=\"data:image/webp;base64,\";\r\nconst BG3=\"data:image/jpeg;base64,\";\r\nconst BG4=\"data:image/jpeg;base64,\";\r\nconst BG5=\"data:image/jpeg;base64,\";\r\nconst bgUni = {\r\n  t:{value:0}, mx:{value:0}, my:{value:0},\r\n  w2:{value:0}, wS:{value:0}, w3:{value:0}, w4:{value:0},\r\n  glow:{value:0}, rise:{value:0},\r\n  scrA:{value:innerWidth/innerHeight}, imgA:{value:1920/1080},\r\n  tex1:{value:loadTex(BG1)}, tex2:{value:loadTex(BG2)},\r\n  tex3:{value:loadTex(BG3)}, tex4:{value:loadTex(BG4)},\r\n  tex5:{value:loadTex(BG5)}\r\n};\r\nconst bgMat = new THREE.ShaderMaterial({\r\n  uniforms:bgUni, depthWrite:false, depthTest:false,\r\n  vertexShader:`varying vec2 vUv;void main(){vUv=uv;gl_Position=vec4(position,1.);}`,\r\n  fragmentShader:`\r\n    varying vec2 vUv;\r\n    uniform float t,mx,my,w2,wS,w3,w4,glow,rise,scrA,imgA;\r\n    uniform sampler2D tex1,tex2,tex3,tex4,tex5;\r\n    float h(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453);}\r\n    float n(vec2 p){vec2 i=floor(p),f=fract(p);f=f*f*(3.-2.*f);\r\n      return mix(mix(h(i),h(i+vec2(1,0)),f.x),mix(h(i+vec2(0,1)),h(i+vec2(1,1)),f.x),f.y);}\r\n    float fbm(vec2 p){float v=0.,a=.5;for(int i=0;i<5;i++){v+=a*n(p);p*=2.04;a*=.5;}return v;}\r\n    vec3 hsv(float h,float s,float v){vec3 k=abs(mod(h*6.+vec3(0,4,2),6.)-3.)-1.;return v*mix(vec3(1.),clamp(k,0.,1.),s);}\r\n    vec2 coverUV(vec2 uv, float zoom, vec2 off){\r\n      vec2 region = scrA>imgA ? vec2(1., imgA/scrA) : vec2(scrA/imgA, 1.);\r\n      return (uv-.5)*region/zoom + .5 + off;\r\n    }\r\n    void main(){\r\n      vec2 uv=vUv;\r\n      float nz=fbm(uv*3.+t*.05);\r\n      vec2 par=vec2(mx*.014, my*.011);\r\n      float uw=1.-max(wS,w3); /* underwater amount */\r\n      vec2 wobble=vec2(sin(uv.y*34.+t*1.1), cos(uv.x*30.-t*.9))*.0032*uw;\r\n      vec2 uvA=coverUV(uv,1.10+rise*.04, par+wobble+vec2(0.,-rise*.05));\r\n      vec2 uvB=coverUV(uv,1.14-rise*.03, par*1.2+wobble+vec2(0., .04-rise*.07));\r\n      vec2 uvS=coverUV(uv,1.10+wS*.05,  par*1.5+vec2(sin(t*.04)*.012, .02-(rise-.46)*.05));\r\n      /* 花のシーン: 風で揺れる(手前ほど大きく、突風はノイズで) */\r\n      float gust=fbm(vec2(t*.16, uv.y*1.8))+.35;\r\n      float wind=(sin(t*1.25+uv.y*9.)+sin(t*.58+uv.x*13.+1.7))*.5;\r\n      vec2 sway=vec2(wind*(.0022+.0036*(1.-uv.y))*gust,\r\n                     sin(t*1.7+uv.x*11.)*.0011*gust);\r\n      vec2 uvC=coverUV(uv,1.16-w3*.06,  par*1.4+vec2(0., .05-(rise-.66)*.10))+sway*w3;\r\n      vec2 uvD=coverUV(uv,1.12-w4*.05,  par*1.4+vec2(0., .03-(rise-.9)*.08))+sway*w4;\r\n      vec3 s1=texture2D(tex1,uvA).rgb;\r\n      vec3 s2=texture2D(tex2,uvB).rgb;\r\n      vec3 sS=texture2D(tex5,uvS).rgb;\r\n      vec3 s3=texture2D(tex3,uvC).rgb;\r\n      vec3 s4=texture2D(tex4,uvD).rgb;\r\n      /* sea reveal: from above */\r\n      float m2=clamp(w2*1.9-(1.-uv.y)*.7+(nz-.5)*.34,0.,1.)*smoothstep(0.,.06,w2);\r\n      /* space reveal: iris wipe from center (土星の渦から宇宙が開く) */\r\n      float dC=length((uv-.5)*vec2(scrA,1.))/1.2;\r\n      float mS=clamp(wS*2.1-dC*1.5+(nz-.5)*.3,0.,1.)*smoothstep(0.,.06,wS);\r\n      /* garden reveal: from above */\r\n      float m3=clamp(w3*1.9-(1.-uv.y)*.7+(nz-.5)*.38,0.,1.)*smoothstep(0.,.06,w3);\r\n      float m4=clamp(w4*1.7-(1.-uv.y)*.5+(nz-.5)*.3 ,0.,1.)*smoothstep(0.,.06,w4);\r\n      m2=smoothstep(0.,1.,m2);mS=smoothstep(0.,1.,mS);m3=smoothstep(0.,1.,m3);m4=smoothstep(0.,1.,m4);\r\n      vec3 col=mix(mix(mix(mix(s1,s2,m2),sS,mS),s3,m3),s4,m4);\r\n      /* glowing seams on transition edges */\r\n      float seamS=(1.-abs(mS*2.-1.))*wS*(1.-wS)*4.;\r\n      col+=vec3(.55,.45,1.)*seamS*.16;\r\n      float seam=(1.-abs(m3*2.-1.))*w3*(1.-w3)*4.;\r\n      col+=hsv(fract(uv.x*.8+t*.05),.6,1.)*seam*.18;\r\n      /* deep-sea haze */\r\n      col+=vec3(.04,.10,.26)*nz*uw*.5*(1.-uv.y*.5);\r\n      /* prism aurora in bloom */\r\n      vec3 rainbow=hsv(fract(uv.x*.7+nz*.4+t*.02),.7,1.);\r\n      col=mix(col,col+rainbow*.22,glow*smoothstep(.25,.9,nz));\r\n      float lum=dot(col,vec3(.299,.587,.114));\r\n      col=mix(vec3(lum),col,1.12);\r\n      float vg=smoothstep(1.3,.38,length(uv-.5));\r\n      gl_FragColor=vec4(col*vg,1.);\r\n    }`\r\n});\r\nconst bgScene=new THREE.Scene(); const bgCam=new THREE.Camera();\r\nbgScene.add(new THREE.Mesh(new THREE.PlaneGeometry(2,2), bgMat));\r\n\r\n/* ---------- post overlay: grain + scanline + vignette ---------- */\r\nconst postUni={t:{value:0},amt:{value:.5}};\r\nconst postMat=new THREE.ShaderMaterial({\r\n  uniforms:postUni,transparent:true,depthWrite:false,depthTest:false,\r\n  vertexShader:`varying vec2 vUv;void main(){vUv=uv;gl_Position=vec4(position,1.);}`,\r\n  fragmentShader:`\r\n    varying vec2 vUv;uniform float t,amt;\r\n    float h(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7))+t)*43758.5453);}\r\n    void main(){\r\n      float g=(h(vUv*vec2(820.,460.))-.5)*.085*amt;\r\n      float scan=sin(vUv.y*900.)* .018*amt;\r\n      float vg=smoothstep(.32,1.05,length(vUv-.5))*.5;\r\n      vec3 col=vec3(g+scan);\r\n      gl_FragColor=vec4(col-vec3(vg*.35), .9);\r\n    }`,\r\n  blending:THREE.AdditiveBlending\r\n});\r\n/* additive can't darken → separate vignette quad with normal blending */\r\nconst vigMat=new THREE.ShaderMaterial({\r\n  transparent:true,depthWrite:false,depthTest:false,\r\n  vertexShader:`varying vec2 vUv;void main(){vUv=uv;gl_Position=vec4(position,1.);}`,\r\n  fragmentShader:`varying vec2 vUv;\r\n    void main(){float vg=smoothstep(.42,1.08,length(vUv-.5));\r\n    gl_FragColor=vec4(0.,0.,0.,vg*.55);}`\r\n});\r\nconst postScene=new THREE.Scene();\r\npostScene.add(new THREE.Mesh(new THREE.PlaneGeometry(2,2), vigMat));\r\npostScene.add(new THREE.Mesh(new THREE.PlaneGeometry(2,2), postMat));\r\n\r\n/* ---------- textures ---------- */\r\nfunction radialTex(stops){\r\n  const c=document.createElement(\"canvas\");c.width=c.height=128;\r\n  const g=c.getContext(\"2d\"),gr=g.createRadialGradient(64,64,0,64,64,64);\r\n  stops.forEach(s=>gr.addColorStop(s[0],s[1]));\r\n  g.fillStyle=gr;g.fillRect(0,0,128,128);\r\n  return new THREE.CanvasTexture(c);\r\n}\r\nconst dotTex = radialTex([[0,\"rgba(255,255,255,1)\"],[.35,\"rgba(190,200,255,.55)\"],[1,\"rgba(0,0,0,0)\"]]);\r\nfunction streakTex(){\r\n  const c=document.createElement(\"canvas\");c.width=16;c.height=128;\r\n  const g=c.getContext(\"2d\");\r\n  const gr=g.createLinearGradient(0,0,0,128);\r\n  gr.addColorStop(0,\"rgba(255,255,255,0)\");gr.addColorStop(.5,\"rgba(255,255,255,.9)\");gr.addColorStop(1,\"rgba(255,255,255,0)\");\r\n  g.fillStyle=gr;g.fillRect(5,0,6,128);\r\n  return new THREE.CanvasTexture(c);\r\n}\r\nfunction bokehTex(){\r\n  const c=document.createElement(\"canvas\");c.width=c.height=256;\r\n  const g=c.getContext(\"2d\");\r\n  const gr=g.createRadialGradient(128,128,0,128,128,120);\r\n  gr.addColorStop(0,\"rgba(255,255,255,.95)\");\r\n  gr.addColorStop(.5,\"rgba(255,255,255,.28)\");\r\n  gr.addColorStop(.82,\"rgba(255,255,255,.42)\"); /* bokeh ring */\r\n  gr.addColorStop(1,\"rgba(255,255,255,0)\");\r\n  g.fillStyle=gr;g.beginPath();g.arc(128,128,120,0,Math.PI*2);g.fill();\r\n  return new THREE.CanvasTexture(c);\r\n}\r\nconst petalTex=bokehTex();\r\n\r\n/* ============================================================\r\n   Iridescent core sphere — clean, no morph\r\n   ============================================================ */\r\nconst coreUni={ t:{value:0}, awaken:{value:0},\r\n  rimA:{value:new THREE.Color(0x8b7bff)}, rimB:{value:new THREE.Color(0xff4fa3)} };\r\nconst coreMat=new THREE.ShaderMaterial({\r\n  uniforms:coreUni, transparent:true,\r\n  vertexShader:`\r\n    varying vec3 vN,vV;\r\n    void main(){\r\n      vec4 mv=modelViewMatrix*vec4(position,1.);\r\n      vN=normalize(normalMatrix*normal);\r\n      vV=normalize(-mv.xyz);\r\n      gl_Position=projectionMatrix*mv;\r\n    }`,\r\n  fragmentShader:`\r\n    varying vec3 vN,vV;\r\n    uniform float t,awaken;uniform vec3 rimA,rimB;\r\n    void main(){\r\n      float dv=max(dot(vN,vV),0.);\r\n      float fr=pow(1.-dv,2.4);\r\n      vec3 base=mix(vec3(.012,.018,.05),vec3(.05,.04,.13),awaken);\r\n      float hueShift=dv*4.+vN.y*2.;\r\n      vec3 iri=mix(rimA,rimB,.5+.5*sin(hueShift+t*.6));\r\n      iri=mix(iri,vec3(.45,.85,1.),.5+.5*sin(hueShift*1.7-t*.4));\r\n      vec3 col=base + iri*fr*(.12+awaken*1.7) + rimA*awaken*.2*pow(dv,2.);\r\n      gl_FragColor=vec4(col,.94);\r\n    }`\r\n});\r\nconst coreMesh=new THREE.Mesh(new THREE.SphereGeometry(3.1, 64, 64), coreMat);\r\nscene.add(coreMesh);\r\nconst haloMat=new THREE.SpriteMaterial({map:dotTex,color:0x8b7bff,transparent:true,opacity:0,blending:THREE.AdditiveBlending,depthWrite:false});\r\nconst halo=new THREE.Sprite(haloMat);halo.scale.set(16,16,1);scene.add(halo);\r\n\r\n/* ============================================================\r\n   Ambient particles\r\n   ============================================================ */\r\nconst PN = lowPower ? (mobile ? 1400 : 3400) : 5200;\nconst pGeo=new THREE.BufferGeometry();\r\nconst pPos=new Float32Array(PN*3), pSeed=new Float32Array(PN), pHue=new Float32Array(PN);\r\nfor(let i=0;i<PN;i++){\r\n  const r=10+Math.random()*46, th=Math.random()*Math.PI*2, ph=Math.acos(2*Math.random()-1);\r\n  pPos[i*3]=r*Math.sin(ph)*Math.cos(th);\r\n  pPos[i*3+1]=(Math.random()-.5)*54;\r\n  pPos[i*3+2]=r*Math.sin(ph)*Math.sin(th)-6;\r\n  pSeed[i]=Math.random()*1000; pHue[i]=Math.random();\r\n}\r\npGeo.setAttribute(\"position\",new THREE.BufferAttribute(pPos,3));\r\npGeo.setAttribute(\"seed\",new THREE.BufferAttribute(pSeed,1));\r\npGeo.setAttribute(\"hue\",new THREE.BufferAttribute(pHue,1));\r\nconst pUni={t:{value:0},vortex:{value:0},rise:{value:0},bright:{value:.35},rainbow:{value:0},px:{value:renderer.getPixelRatio()}};\r\nconst pMat=new THREE.ShaderMaterial({\r\n  uniforms:pUni,transparent:true,depthWrite:false,blending:THREE.AdditiveBlending,\r\n  vertexShader:`\r\n    attribute float seed,hue;varying float vA,vHue;\r\n    uniform float t,vortex,rise,px;\r\n    void main(){\r\n      vec3 p=position;\r\n      float s=seed;\r\n      p.x+=sin(t*.25+s)*1.2; p.y+=cos(t*.2+s*1.3)*1.2; p.z+=sin(t*.18+s*.7)*1.2;\r\n      float r=length(p.xz);\r\n      float ang=atan(p.z,p.x)+vortex*(2.2+10./(r+2.))*1.2;\r\n      float rr=mix(r, max(r*.42,5.5), vortex);\r\n      p.x=cos(ang)*rr; p.z=sin(ang)*rr;\r\n      p.y=mix(p.y,p.y*.32,vortex);\r\n      p.y+=rise*(14.+mod(s,9.));\r\n      vec4 mv=modelViewMatrix*vec4(p,1.);\r\n      float sz=(1.1+fract(s)*1.9)*px;\r\n      gl_PointSize=sz*(140./-mv.z);\r\n      vA=smoothstep(95.,15.,-mv.z);\r\n      vHue=hue;\r\n      gl_Position=projectionMatrix*mv;\r\n    }`,\r\n  fragmentShader:`\r\n    varying float vA,vHue;uniform float bright,rainbow,t;\r\n    vec3 hsv(float h,float s,float v){vec3 k=abs(mod(h*6.+vec3(0,4,2),6.)-3.)-1.;return v*mix(vec3(1.),clamp(k,0.,1.),s);}\r\n    void main(){\r\n      float d=length(gl_PointCoord-.5);\r\n      float a=smoothstep(.5,.05,d)*vA*bright;\r\n      vec3 base=mix(vec3(.55,.62,1.),vec3(1.,.45,.75),step(.86,fract(vHue*7.)));\r\n      vec3 rb=hsv(fract(vHue+t*.03),.75,1.);\r\n      gl_FragColor=vec4(mix(base,rb,rainbow),a);\r\n    }`\r\n});\r\nconst points=new THREE.Points(pGeo,pMat);scene.add(points);\r\n\r\n/* ============================================================\r\n   Saturn ring\r\n   ============================================================ */\r\nconst RN=lowPower ? (mobile ? 1500 : 3600) : 5200;\nconst rGeo=new THREE.BufferGeometry();\r\nconst rPos=new Float32Array(RN*3), rSeed=new Float32Array(RN);\r\nfor(let i=0;i<RN;i++){\r\n  const a=Math.random()*Math.PI*2, rad=5.2+Math.pow(Math.random(),1.6)*4.2;\r\n  rPos[i*3]=Math.cos(a)*rad; rPos[i*3+1]=(Math.random()-.5)*.34; rPos[i*3+2]=Math.sin(a)*rad;\r\n  rSeed[i]=Math.random()*1000;\r\n}\r\nrGeo.setAttribute(\"position\",new THREE.BufferAttribute(rPos,3));\r\nrGeo.setAttribute(\"seed\",new THREE.BufferAttribute(rSeed,1));\r\nconst rUni={t:{value:0},on:{value:0},spin:{value:0},px:{value:renderer.getPixelRatio()}};\r\nconst rMat=new THREE.ShaderMaterial({\r\n  uniforms:rUni,transparent:true,depthWrite:false,blending:THREE.AdditiveBlending,\r\n  vertexShader:`\r\n    attribute float seed;varying float vA,vS;\r\n    uniform float t,on,spin,px;\r\n    void main(){\r\n      vec3 p=position;\r\n      float ang=spin*(1.4+fract(seed)*.5);\r\n      float c=cos(ang),s=sin(ang);\r\n      p.xz=mat2(c,-s,s,c)*p.xz;\r\n      p.y+=sin(t*2.+seed)*.06;\r\n      vec4 mv=modelViewMatrix*vec4(p,1.);\r\n      gl_PointSize=(1.+fract(seed*3.)*1.6)*px*(150./-mv.z)*on;\r\n      vA=on; vS=seed;\r\n      gl_Position=projectionMatrix*mv;\r\n    }`,\r\n  fragmentShader:`\r\n    varying float vA,vS;\r\n    void main(){\r\n      float d=length(gl_PointCoord-.5);\r\n      float a=smoothstep(.5,.04,d)*vA;\r\n      vec3 col=mix(vec3(.62,.55,1.),vec3(1.,.5,.78),step(.7,fract(vS*5.)));\r\n      col=mix(col,vec3(1.,.92,.7),step(.93,fract(vS*11.)));\r\n      gl_FragColor=vec4(col,a*.9);\r\n    }`\r\n});\r\nconst ring=new THREE.Points(rGeo,rMat);\r\nring.rotation.x=.42; ring.rotation.z=.12;\r\nscene.add(ring);\r\n\r\n/* ============================================================\r\n   Ascent streaks (ch4) — speed lines like a game boost\r\n   ============================================================ */\r\nconst SN_=lowPower ? (mobile ? 60 : 140) : 200;\nconst sGeo=new THREE.BufferGeometry();\r\nconst sPos=new Float32Array(SN_*3), sSeed=new Float32Array(SN_);\r\nfor(let i=0;i<SN_;i++){\r\n  sPos[i*3]=(Math.random()-.5)*60;\r\n  sPos[i*3+1]=(Math.random()-.5)*70;\r\n  sPos[i*3+2]=(Math.random()-.5)*40-4;\r\n  sSeed[i]=Math.random()*100;\r\n}\r\nsGeo.setAttribute(\"position\",new THREE.BufferAttribute(sPos,3));\r\nsGeo.setAttribute(\"seed\",new THREE.BufferAttribute(sSeed,1));\r\nconst sUni={t:{value:0},on:{value:0},px:{value:renderer.getPixelRatio()}};\r\nconst sMat=new THREE.ShaderMaterial({\r\n  uniforms:sUni,transparent:true,depthWrite:false,blending:THREE.AdditiveBlending,\r\n  vertexShader:`\r\n    attribute float seed;varying float vA,vS;\r\n    uniform float t,on,px;\r\n    void main(){\r\n      vec3 p=position;\r\n      p.y=mod(p.y - t*(22.+fract(seed)*26.)*on + 200., 70.)-35.;\r\n      vec4 mv=modelViewMatrix*vec4(p,1.);\r\n      gl_PointSize=(20.+fract(seed*3.)*26.)*px*(60./-mv.z)*on;\r\n      vA=on*smoothstep(80.,18.,-mv.z); vS=seed;\r\n      gl_Position=projectionMatrix*mv;\r\n    }`,\r\n  fragmentShader:`\r\n    varying float vA,vS;uniform sampler2D map;\r\n    void main(){\r\n      vec2 uv=gl_PointCoord;\r\n      float a=texture2D(map,uv).a*vA*.5;\r\n      vec3 col=mix(vec3(.7,.62,1.),vec3(1.,.6,.85),fract(vS*3.));\r\n      gl_FragColor=vec4(col,a);\r\n    }`\r\n});\r\nsMat.uniforms.map={value:streakTex()};\r\nconst streaks=new THREE.Points(sGeo,sMat);scene.add(streaks);\r\n\r\n/* ============================================================\r\n   Glass jellyfish (procedural — GLB差し替え可)\r\n   ============================================================ */\r\nfunction makeJelly(scale){\r\n  const g=new THREE.Group();\r\n  const domeUni={t:{value:0},op:{value:1}};\r\n  const domeMat=new THREE.ShaderMaterial({\r\n    uniforms:domeUni,transparent:true,side:THREE.DoubleSide,depthWrite:false,\r\n    vertexShader:`\r\n      varying vec3 vN,vV;varying float vY;uniform float t;\r\n      void main(){\r\n        vec3 p=position;\r\n        float pulse=sin(t*1.6)*.5+.5;\r\n        p.xz*=1.+pulse*.13*(1.-uv.y);\r\n        p.y*=1.-pulse*.07;\r\n        vY=uv.y;\r\n        vec4 mv=modelViewMatrix*vec4(p,1.);\r\n        vN=normalize(normalMatrix*normal);vV=normalize(-mv.xyz);\r\n        gl_Position=projectionMatrix*mv;\r\n      }`,\r\n    fragmentShader:`\r\n      varying vec3 vN,vV;varying float vY;uniform float t,op;\r\n      void main(){\r\n        float fr=pow(1.-abs(dot(vN,vV)),2.2);\r\n        vec3 col=mix(vec3(.45,.75,1.),vec3(.72,.55,1.),vY);\r\n        col+=vec3(1.,.5,.8)*pow(fr,2.)*.6;\r\n        float a=(fr*.85+.05)*op;\r\n        gl_FragColor=vec4(col,a);\r\n      }`\r\n  });\r\n  const dome=new THREE.Mesh(new THREE.SphereGeometry(1,28,20,0,Math.PI*2,0,Math.PI/1.9),domeMat);\r\n  dome.scale.y=.75; g.add(dome);\r\n  const tents=[];\r\n  for(let i=0;i<9;i++){\r\n    const segs=14, pos=new Float32Array(segs*3);\r\n    const geo=new THREE.BufferGeometry();\r\n    geo.setAttribute(\"position\",new THREE.BufferAttribute(pos,3));\r\n    const mat=new THREE.LineBasicMaterial({color:0x9fd2ff,transparent:true,opacity:.34,blending:THREE.AdditiveBlending});\r\n    const line=new THREE.Line(geo,mat);\r\n    const a=i/9*Math.PI*2, rad=.55+Math.random()*.25;\r\n    line.userData={a,rad,ph:Math.random()*9,segs};\r\n    tents.push(line);g.add(line);\r\n  }\r\n  g.scale.setScalar(scale);\r\n  g.userData={domeUni,tents};\r\n  return g;\r\n}\r\nconst jellies=[];\r\n[{x:-9,y:3.5,z:-4,s:1.5,sp:.5},{x:10,y:-4,z:-9,s:1.05,sp:.7},{x:-5,y:-7,z:2,s:.7,sp:.9}].forEach(d=>{\r\n  const j=makeJelly(d.s); j.position.set(d.x,d.y,d.z); j.userData.def=d;\r\n  jellies.push(j); scene.add(j);\r\n});\r\n\r\n/* ============================================================\r\n   Rainbow flowers (ch4)\r\n   ============================================================ */\r\nconst FN=lowPower ? (mobile ? 24 : 46) : 64;\nconst flowers=[];\r\nfor(let i=0;i<FN;i++){\r\n  const c=new THREE.Color().setHSL(i/FN,.85,.66);\r\n  const m=new THREE.SpriteMaterial({map:petalTex,color:c,transparent:true,opacity:0,blending:THREE.AdditiveBlending,depthWrite:false});\r\n  const s=new THREE.Sprite(m);\r\n  const a=Math.random()*Math.PI*2, r=3+Math.random()*16;\r\n  s.position.set(Math.cos(a)*r,(Math.random()-.5)*16,Math.sin(a)*r-3);\r\n  s.userData={base:.8+Math.random()*2.6,ph:Math.random()*9,rise:6+Math.random()*16};\r\n  s.scale.setScalar(0);\r\n  flowers.push(s);scene.add(s);\r\n}\r\n\r\n/* ============================================================\r\n   Falling petals — foreground 2D layer with depth & DOF blur\r\n   (花の背景が現れたら、手前と奥に大小の花びらが降る)\r\n   ============================================================ */\r\nconst pcv=document.getElementById(\"petals\");\r\nconst pctx=pcv.getContext(\"2d\");\r\nlet PW=0,PH=0,PDPR=1;\nfunction petalResize(){\n  PDPR=Math.min(devicePixelRatio || 1, lowPower ? 1.08 : 1.3);\n  PW=innerWidth; PH=innerHeight;\n  pcv.width=PW*PDPR; pcv.height=PH*PDPR;\n  pctx.setTransform(PDPR,0,0,PDPR,0,0);\n}\npetalResize();\r\nfunction makePetalSprite(color,glow,blur){\r\n  const s=blur?112:72, c=document.createElement(\"canvas\");\r\n  c.width=c.height=s;\r\n  const g=c.getContext(\"2d\");\r\n  if(blur) g.filter=\"blur(6px)\";\r\n  g.translate(s/2,s/2);\r\n  const r=blur?30:24;\r\n  const gr=g.createRadialGradient(0,-r*.25,2,0,0,r);\r\n  gr.addColorStop(0,\"rgba(255,255,255,.95)\");\r\n  gr.addColorStop(.4,color);\r\n  gr.addColorStop(1,glow);\r\n  g.fillStyle=gr;\r\n  g.beginPath();\r\n  g.moveTo(0,-r);\r\n  g.bezierCurveTo(r*.85,-r*.55, r*.6,r*.7, 0,r);\r\n  g.bezierCurveTo(-r*.6,r*.7, -r*.85,-r*.55, 0,-r);\r\n  g.fill();\r\n  return c;\r\n}\r\nconst petalSprites={\r\n  sharp:[\r\n    makePetalSprite(\"rgba(255,170,214,.9)\",\"rgba(255,79,163,0)\",false),\r\n    makePetalSprite(\"rgba(214,180,255,.9)\",\"rgba(139,123,255,0)\",false),\r\n    makePetalSprite(\"rgba(255,236,244,.92)\",\"rgba(255,210,230,0)\",false)\r\n  ],\r\n  blur:[\r\n    makePetalSprite(\"rgba(255,170,214,.8)\",\"rgba(255,79,163,0)\",true),\r\n    makePetalSprite(\"rgba(214,180,255,.8)\",\"rgba(139,123,255,0)\",true)\r\n  ]\r\n};\r\nconst PETN=lowPower ? (mobile ? 20 : 40) : 54;\nconst petals=[];\r\nfor(let i=0;i<PETN;i++){\r\n  const depth=Math.random();\r\n  petals.push({\r\n    x:Math.random()*innerWidth, y:Math.random()*innerHeight,\r\n    depth, blur:depth>.78,\r\n    spr:depth>.78? petalSprites.blur[i%2] : petalSprites.sharp[i%3],\r\n    spd:.45+depth*1.7+Math.random()*.4,\r\n    swayP:Math.random()*9, swayA:.25+depth*.8,\r\n    rot:Math.random()*6.28, vr:(Math.random()-.5)*.02\r\n  });\r\n}\r\nlet petalAlpha=0;\r\nfunction petalsDraw(t,target,mxN){\r\n  petalAlpha+=(target-petalAlpha)*.05;\r\n  if(petalAlpha<.01){ if(pcv.dataset.on===\"1\"){pctx.clearRect(0,0,PW,PH);pcv.dataset.on=\"0\";} return; }\r\n  pcv.dataset.on=\"1\";\r\n  pctx.clearRect(0,0,PW,PH);\r\n  petals.forEach(pt=>{\r\n    pt.y+=pt.spd; pt.rot+=pt.vr;\r\n    pt.x+=Math.sin(t*.8+pt.swayP)*pt.swayA + mxN*pt.depth*.6\r\n        + Math.sin(t*.45)*(.25+pt.depth*.55); /* 風の突風と同期 */\r\n    if(pt.y>PH+60){pt.y=-60;pt.x=Math.random()*PW;}\r\n    if(pt.x>PW+80)pt.x=-80; if(pt.x<-80)pt.x=PW+80;\r\n    const sz=(11+pt.depth*44);\r\n    const a=petalAlpha*(pt.blur? .5 : .38+pt.depth*.5);\r\n    pctx.globalAlpha=a;\r\n    pctx.save();\r\n    pctx.translate(pt.x,pt.y);\r\n    pctx.rotate(pt.rot+Math.sin(t*.6+pt.swayP)*.5);\r\n    pctx.drawImage(pt.spr,-sz/2,-sz/2,sz,sz);\r\n    pctx.restore();\r\n  });\r\n  pctx.globalAlpha=1;\r\n}\r\n\r\n/* ============================================================\r\n   Scroll & loop\r\n   ============================================================ */\r\nconst caps=[1,2,3,4].map(i=>document.getElementById(\"cap\"+i));\r\nconst scrollHint=document.getElementById(\"scrollHint\");\r\nconst navBtns=[...document.querySelectorAll(\".cn\")];\r\nconst hudDepth=document.getElementById(\"hudDepth\");\r\nconst hudChap=document.getElementById(\"hudChap\");\r\nlet scrollP=0, targetP=0, virtualP=0, touchY=null;\r\n\r\nfunction storyHeight(){return document.getElementById(\"story\").offsetHeight - innerHeight;}\r\nfunction band(p,a,b,fade){\r\n  const f=fade||.045;\r\n  return Math.min(Math.max((p-a)/f,0),1,Math.max((b-p)/f,0));\r\n}\r\nconst clamp01=v=>Math.min(1,Math.max(0,v));\r\nconst smooth=v=>v*v*(3-2*v);\r\n\r\nfunction applyProgressState(){\r\n  const realP=clamp01(scrollY/Math.max(1,storyHeight()));\r\n  if(scrollY>4) virtualP=realP;\r\n  targetP=clamp01(Math.max(realP,virtualP));\r\n  const scrolled=targetP>.012 || scrollY>40;\r\n  document.body.classList.toggle(\"scrolled\",scrolled); document.querySelector(\".viviris-custom-element-root\")?.classList.toggle(\"scrolled\",scrolled);\r\n}\r\naddEventListener(\"scroll\",applyProgressState,{passive:true});\r\naddEventListener(\"wheel\",e=>{\r\n  const max=Math.max(1600,storyHeight());\r\n  virtualP=clamp01(virtualP + e.deltaY/max);\r\n  applyProgressState();\r\n},{passive:true});\r\naddEventListener(\"touchstart\",e=>{touchY=e.touches&&e.touches[0]?e.touches[0].clientY:null;},{passive:true});\r\naddEventListener(\"touchmove\",e=>{\r\n  if(touchY==null || !e.touches || !e.touches[0]) return;\r\n  const y=e.touches[0].clientY;\r\n  const max=Math.max(1600,storyHeight());\r\n  virtualP=clamp01(virtualP + (touchY-y)/max);\r\n  touchY=y;\r\n  applyProgressState();\r\n},{passive:true});\r\napplyProgressState();\r\n\r\nnavBtns.forEach(btn=>{\n  btn.addEventListener(\"click\",()=>{\n    const i=+btn.dataset.go;\n    const behavior=reduced?\"auto\":\"smooth\";\n    const anchors=[0,.27,.5,.74,.94];\n    virtualP=targetP=anchors[i]||0;\n    applyProgressState();\n    if(i===4){document.getElementById(\"landing\").scrollIntoView({behavior});return;}\n    scrollTo({top:(anchors[i]||0)*storyHeight(),behavior});\n  });\n});\r\nlet mx=0,my=0,mxT=0,myT=0;\r\naddEventListener(\"pointermove\",e=>{\r\n  mxT=(e.clientX/innerWidth-.5)*2; myT=(e.clientY/innerHeight-.5)*2;\r\n},{passive:true});\r\n\r\nconst chapNames=[\"CH.01 / 深海\",\"CH.02 / 灯火\",\"CH.03 / 土星\",\"CH.04 / 開花上昇\",\"CH.05 / 共創\"];\r\nlet hudTick=0;\r\n/* scroll velocity → 3D rotation of card grids (Active Theory work風) */\r\nlet lastSY=scrollY, sVel=0;\r\n\r\nconst clock=new THREE.Clock();\r\nconst tmpA=new THREE.Color(), tmpB=new THREE.Color();\r\nlet rafPending=false;\r\nfunction queueFrame(){\r\n  if(rafPending || typeof requestAnimationFrame!==\"function\") return;\r\n  rafPending=true;\r\n  requestAnimationFrame(()=>{rafPending=false;frame();});\r\n}\r\nfunction frame(){\r\n  queueFrame();\r\n  applyProgressState();\r\n  const t=clock.getElapsedTime();\r\n  scrollP+=(targetP-scrollP)*.07;\r\n  const p=scrollP;\r\n  mx+=(mxT-mx)*.05; my+=(myT-my)*.05;\r\n\r\n  /* grid scroll-rotation */\r\n  const sy=scrollY + virtualP*Math.max(1,storyHeight());\r\n  sVel+=((sy-lastSY)-sVel)*.12; lastSY=sy;\r\n  const srot=reduced?0:Math.max(-13,Math.min(13,sVel*.16));\r\n  document.documentElement.style.setProperty(\"--srot\",srot.toFixed(2));\r\n  updateTiltCards(srot);\r\n  updateWorkSpiral();\r\n\r\n  const c1=clamp01(p/.24);\r\n  const c2=clamp01((p-.24)/.22);\r\n  const c3=clamp01((p-.46)/.22);\r\n  const c4=clamp01((p-.68)/.24);\r\n  const land=clamp01((p-.9)/.1);\r\n\r\n  caps[0].style.opacity=band(p,.015,.2);\r\n  if(scrollHint){\r\n    const hint=band(p,.006,.105,.026);\r\n    scrollHint.style.opacity=hint.toFixed(3);\r\n    scrollHint.style.filter=`blur(${((1-hint)*10).toFixed(2)}px)`;\r\n  }\r\n  caps[1].style.opacity=band(p,.27,.42);\r\n  caps[2].style.opacity=band(p,.5,.64);\r\n  caps[3].style.opacity=band(p,.72,.86);\r\n  const act=p<.24?0:p<.46?1:p<.68?2:p<.94?3:4;\r\n  navBtns.forEach((b,i)=>{\n    const current=i===act;\n    b.classList.toggle(\"act\",current);\n    if(current){b.setAttribute(\"aria-current\",\"true\");}\n    else{b.removeAttribute(\"aria-current\");}\n  });\n\r\n  /* HUD readout (every ~6 frames) */\r\n  if(++hudTick%6===0){\r\n    let label;\r\n    if(p<.68){ label=\"DEPTH -\"+Math.max(0,Math.round((1-p/.68)*1800))+\"m\"; }\r\n    else { label=\"ALT +\"+Math.round(((p-.68)/.32)*4200)+\"km\"; }\r\n    hudDepth.textContent=label;\r\n    hudChap.textContent=chapNames[act];\r\n  }\r\n\r\n  /* photo environment crossfade */\r\n  bgUni.t.value=t; bgUni.mx.value=mx; bgUni.my.value=my;\r\n  bgUni.w2.value=smooth(clamp01((p-.26)/.18));            // 深海の底 → 光射す海中\r\n  bgUni.wS.value=smooth(clamp01((p-.46)/.14));            // 海 → 宇宙(中心から虹彩ワイプ)\r\n  bgUni.w3.value=smooth(clamp01((p-.66)/.16));            // 宇宙 → 虹色の花園\r\n  bgUni.w4.value=smooth(clamp01((p-.90)/.10));            // 花園 → 未来への小道\r\n  bgUni.glow.value=smooth(c4)*(1-land*.55);\r\n  bgUni.rise.value=p;\r\n  tmpA.copy(COL.abyss).lerp(COL.deep, smooth(c2)*.8);\r\n  tmpA.lerp(COL.nebula, smooth(c3)*(1-smooth(c4)*.5));\r\n  tmpA.lerp(new THREE.Color(0x2a1840), smooth(c4));\r\n  scene.fog.color.copy(tmpA);\r\n  scene.fog.density=.028-.016*c4;\r\n\r\n  postUni.t.value=t;\r\n  postUni.amt.value=.55-land*.25;\r\n\r\n  core.intensity = c2*2.6 + c3*1.4;\r\n  core.color.setHSL(.72-.1*c3,.8,.6);\r\n  pinkL.intensity = c3*1.2 + c4*1.6;\r\n\r\n  /* core sphere */\r\n  coreUni.t.value=t;\r\n  coreUni.awaken.value=smooth(c2)*.85+c3*.15;\r\n  const coreScale=1-smooth(c4)*.55;\r\n  coreMesh.scale.setScalar(Math.max(.001,coreScale));\r\n  coreMesh.position.y=-smooth(c4)*9;\r\n  coreMesh.rotation.y=t*.12+c3*3;\r\n  halo.position.copy(coreMesh.position);\r\n  haloMat.opacity=(smooth(c2)*.5+c3*.25)*(1-smooth(c4));\r\n  haloMat.color.setHSL(.72-.12*c3,.85,.66);\r\n  const hs=16*(1+.06*Math.sin(t*2))*coreScale;\r\n  halo.scale.set(hs,hs,1);\r\n\r\n  rUni.t.value=t;\r\n  rUni.on.value=smooth(c3)*(1-smooth(c4)*.85);\r\n  rUni.spin.value+=(0.004+c3*.075)*(1-c4*.7);\r\n  ring.position.y=coreMesh.position.y;\r\n  ring.scale.setScalar(Math.max(.001,coreScale*(1+c4*1.8)));\r\n\r\n  pUni.t.value=t;\r\n  pUni.vortex.value=smooth(c3)*(1-smooth(c4));\r\n  pUni.rise.value=smooth(c4);\r\n  pUni.bright.value=.3+c2*.5+c4*.3-land*.42;\r\n  pUni.rainbow.value=smooth(c4)*(1-land*.4)+land*.25;\r\n\r\n  sUni.t.value=t;\r\n  sUni.on.value=smooth(c4)*(1-land);\r\n\r\n  jellies.forEach((j,k)=>{\r\n    const d=j.userData.def, U=j.userData;\r\n    U.domeUni.t.value=t*d.sp+k*2;\r\n    const fade=(1-smooth(c3))*(1-smooth(c4));\r\n    U.domeUni.op.value=fade*.95;\r\n    j.position.x=d.x+Math.sin(t*.14*d.sp+k)*1.6+mx*1.2;\r\n    j.position.y=d.y+Math.sin(t*.3*d.sp+k*3)*1.1+smooth(c4)*-12;\r\n    j.position.z=d.z+Math.cos(t*.12+k)*1.2;\r\n    j.rotation.z=Math.sin(t*.2+k)*.16;\r\n    U.tents.forEach(line=>{\r\n      const {a,rad,ph,segs}=line.userData;\r\n      const arr=line.geometry.attributes.position.array;\r\n      for(let s=0;s<segs;s++){\r\n        const f=s/(segs-1);\r\n        arr[s*3]  =Math.cos(a)*rad*(1-f*.25)+Math.sin(t*1.7+ph+f*4)*.16*f;\r\n        arr[s*3+1]=-f*1.9-Math.sin(t*1.6+ph)*.1*f;\r\n        arr[s*3+2]=Math.sin(a)*rad*(1-f*.25)+Math.cos(t*1.5+ph+f*4)*.16*f;\r\n      }\r\n      line.geometry.attributes.position.needsUpdate=true;\r\n      line.material.opacity=.3*U.domeUni.op.value;\r\n    });\r\n  });\r\n\r\n  const bloom=smooth(c4);\r\n  flowers.forEach((f,i)=>{\r\n    const u=f.userData;\r\n    const local=clamp01(bloom*1.5-i/flowers.length*.5);\r\n    const s=u.base*smooth(local)*(1+.08*Math.sin(t*2+u.ph));\r\n    f.scale.setScalar(s);\r\n    f.material.opacity=smooth(local)*.85*(1-land*.45);\r\n    f.position.y+=(local>0? .013+u.rise*.0009:0);\r\n    if(f.position.y>16) f.position.y=-14;\r\n    f.material.rotation=Math.sin(t*.4+u.ph)*.4;\r\n  });\r\n\r\n  camera.position.x=mx*1.6;\r\n  camera.position.y=-my*1.2-smooth(c1)*1.2+smooth(c4)*7-land*2;\r\n  camera.position.z=26-smooth(c3)*4+smooth(c4)*2;\r\n  camera.lookAt(0, coreMesh.position.y*.4+smooth(c4)*5, 0);\r\n\r\n  /* petals fall once the garden appears, and keep falling over ch5 */\r\n  petalsDraw(t, reduced?0:smooth(clamp01((p-.7)/.12))*(1-land*.3), mx*8);\r\n\r\n  renderer.autoClear=false;\r\n  renderer.clear();\r\n  renderer.render(bgScene,bgCam);\r\n  renderer.render(scene,camera);\r\n  renderer.render(postScene,bgCam);\r\n}\r\n\r\naddEventListener(\"resize\",()=>{\n  camera.aspect=innerWidth/innerHeight;\n  camera.updateProjectionMatrix();\n  renderer.setPixelRatio(Math.min(devicePixelRatio || 1, DPR_CAP));\n  renderer.setSize(innerWidth,innerHeight);\n  const px=renderer.getPixelRatio();\n  pUni.px.value=px;\n  rUni.px.value=px;\n  sUni.px.value=px;\n  bgUni.scrA.value=innerWidth/innerHeight;\n  petalResize();\n});\n\r\n/* ============================================================\r\n   Welcome + BGM\r\n   ============================================================ */\r\nconst bgm=document.getElementById(\"bgm\");\r\nbgm.volume=.4;\r\nconst soundBtn=document.getElementById(\"soundBtn\");\r\nlet soundOn=true;\r\nfunction applySound(){\n  soundBtn.classList.toggle(\"on\",soundOn);\n  soundBtn.setAttribute(\"aria-pressed\",String(soundOn));\n  soundBtn.setAttribute(\"aria-label\",soundOn?\"BGMを停止する\":\"BGMを再生する\");\n  if(soundOn){bgm.play().catch(()=>{});}else{bgm.pause();}\n}\nsoundBtn.addEventListener(\"click\",()=>{soundOn=!soundOn;applySound();});\ndocument.getElementById(\"enterBtn\").addEventListener(\"click\",()=>{\n  const welcome=document.getElementById(\"welcome\");\n  const root=document.querySelector(\".viviris-custom-element-root\");\n  if(welcome){welcome.classList.add(\"gone\");}\n  document.body.classList.add(\"entered\"); if(root) root.classList.add(\"entered\",\"user-entered\");\n  document.getElementById(\"landing\").focus({preventScroll:true});\n  if(!reduced && soundOn) bgm.play().catch(()=>{});\n});\nsetInterval(()=>{\r\n  if(bgm.paused)return;\r\n  const want=targetP>.92? .26 : .4;\r\n  bgm.volume+=(want-bgm.volume)*.08;\r\n},120);\r\n\r\n/* ============================================================\r\n   Landing animations\r\n   ============================================================ */\r\n/* char splitter — preserves <br>/<em>/<span>, and keeps 禁則処理\r\n   (句読点や閉じ括弧は直前の文字と同じspanに入れて行頭に来ないようにする) */\r\nlet chIdx=0;\r\nconst KINSOKU=\"、。，．・：；！？!?）」』】〉》ーぁぃぅぇぉっゃゅょ…‥\";\r\nfunction splitNode(node){\r\n  [...node.childNodes].forEach(n=>{\r\n    if(n.nodeType===3){\r\n      const frag=document.createDocumentFragment();\r\n      let last=null;\r\n      [...n.textContent].forEach(ch=>{\r\n        if(ch.trim()===\"\"){frag.appendChild(document.createTextNode(ch));last=null;return;}\r\n        if(last && KINSOKU.includes(ch)){ last.textContent+=ch; return; }\r\n        const s=document.createElement(\"span\");\r\n        s.className=\"ch\";s.textContent=ch;\r\n        s.style.setProperty(\"--i\",Math.min(chIdx++,46));\r\n        frag.appendChild(s);last=s;\r\n      });\r\n      node.replaceChild(frag,n);\r\n    }else if(n.nodeType===1 && n.tagName!==\"BR\"){\r\n      splitNode(n);\r\n    }\r\n  });\r\n}\r\ndocument.querySelectorAll(\".st\").forEach(el=>{chIdx=0;splitNode(el);});\r\n\r\nconst io=new IntersectionObserver(es=>{\r\n  es.forEach(e=>{\r\n    const visible=e.isIntersecting;\r\n    e.target.classList.toggle(\"in\",visible);\r\n    e.target.querySelectorAll(\".st\").forEach(s=>s.classList.toggle(\"in\",visible));\r\n    if(e.target.classList.contains(\"st\"))e.target.classList.toggle(\"in\",visible);\r\n  });\r\n},{threshold:.12});\r\ndocument.querySelectorAll(\".rv,.rule,.marquee\").forEach(el=>io.observe(el));\r\n\r\n/* tilt — Active Theory式: スクロール位置でカードが個別に3D回転 + ホバー追従 */\r\nconst fineP=matchMedia(\"(pointer:fine)\").matches;\r\nconst tiltCards=[...document.querySelectorAll(\".works [data-tilt]\")].map((card,i)=>{\n  const inner=card.querySelector(\".wk-in\")||card;\r\n  const o={card,inner,max:+(card.dataset.tiltMax||8),dir:(i%2?1:-1),hx:0,hy:0,hover:false};\r\n  if(fineP){\r\n    card.addEventListener(\"pointermove\",e=>{\r\n      const r=card.getBoundingClientRect();\r\n      o.hx=(e.clientX-r.left)/r.width-.5;\r\n      o.hy=(e.clientY-r.top)/r.height-.5;\r\n      o.hover=true;\r\n      card.style.setProperty(\"--mx\",((o.hx+.5)*100)+\"%\");\r\n      card.style.setProperty(\"--my\",((o.hy+.5)*100)+\"%\");\r\n    });\r\n    card.addEventListener(\"pointerleave\",()=>{o.hover=false;});\r\n  }\r\n  return o;\r\n});\r\nconst workStage=document.querySelector(\".works\");\r\nconst workCards=[...document.querySelectorAll(\".works .wk\")];\r\nfunction updateWorkSpiral(){\r\n  if(!workStage || !workCards.length || innerWidth<761){\r\n    workCards.forEach(card=>{\r\n      card.style.opacity=\"\";\r\n      [\"--sx\",\"--sy\",\"--sz\",\"--srx\",\"--sry\",\"--srz\",\"--ss\"].forEach(v=>card.style.removeProperty(v));\r\n    });\r\n    return;\r\n  }\r\n  const r=workStage.getBoundingClientRect();\r\n  const vh=innerHeight||1;\r\n  const p=Math.max(0,Math.min(1,(vh*.92-r.top)/(vh+r.height*.85)));\r\n  const eased=p*p*(3-2*p);\r\n  const radius=Math.min(innerWidth*.22,320);\r\n  const depth=Math.min(innerWidth*.2,280);\r\n  const count=Math.max(1,workCards.length);\r\n  workCards.forEach((card,i)=>{\r\n    const base=i/count*Math.PI*2;\r\n    const theta=base+eased*Math.PI*2.15-Math.PI*.52;\r\n    const front=(Math.cos(theta)+1)/2;\r\n    const x=Math.sin(theta)*radius;\r\n    const z=Math.cos(theta)*depth+front*135-165;\r\n    const y=(i-(count-1)/2)*112+Math.sin(theta*1.08+eased*Math.PI)*34-eased*24;\r\n    const rx=5+Math.sin(theta+eased*Math.PI)*7;\r\n    const ry=-Math.sin(theta)*38+Math.cos(eased*Math.PI*2+i)*4;\r\n    const rz=Math.sin(theta*1.6)*5;\r\n    const scale=.82+front*.27;\r\n    card.style.setProperty(\"--sx\",x.toFixed(1)+\"px\");\r\n    card.style.setProperty(\"--sy\",y.toFixed(1)+\"px\");\r\n    card.style.setProperty(\"--sz\",z.toFixed(1)+\"px\");\r\n    card.style.setProperty(\"--srx\",rx.toFixed(2)+\"deg\");\r\n    card.style.setProperty(\"--sry\",ry.toFixed(2)+\"deg\");\r\n    card.style.setProperty(\"--srz\",rz.toFixed(2)+\"deg\");\r\n    card.style.setProperty(\"--ss\",scale.toFixed(3));\r\n    card.style.opacity=String((.56+front*.44).toFixed(3));\r\n    card.style.zIndex=String(20+Math.round(front*30));\r\n  });\r\n}\r\nfunction updateTiltCards(srot){\r\n  if(reduced)return;\r\n  const vh=innerHeight, vc=vh*.5;\r\n  tiltCards.forEach(o=>{\r\n    const r=o.card.getBoundingClientRect();\r\n    if(r.bottom<-260||r.top>vh+260){return;}\r\n    /* 螺旋: 縦位置でピッチ + 交互方向のヨー&ロール + 中央で手前へ膨らむ */\r\n    const rel=((r.top+r.height*.5)-vc)/vh;\r\n    const baseRX=rel*-18 + srot*.8;\r\n    const baseRY=rel*26*o.dir + srot*.35*o.dir;\r\n    const baseRZ=rel*6*o.dir;\r\n    const z=(1-Math.min(1,Math.abs(rel)*2))*28;\r\n    const hRX=o.hover? -o.hy*o.max:0;\r\n    const hRY=o.hover?  o.hx*o.max:0;\r\n    o.inner.style.transform=\r\n      `translateZ(${(z+(o.hover?12:0)).toFixed(1)}px) `+\r\n      `rotateX(${(baseRX+hRX).toFixed(2)}deg) `+\r\n      `rotateY(${(baseRY+hRY).toFixed(2)}deg) `+\r\n      `rotateZ(${baseRZ.toFixed(2)}deg)`;\r\n  });\r\n}\r\n/* グリッチコピーに本画像を流し込む(ファイル容量節約のためJSで複製) */\r\naddEventListener(\"scroll\",updateWorkSpiral,{passive:true});\r\naddEventListener(\"resize\",updateWorkSpiral,{passive:true});\r\nupdateWorkSpiral();\r\ndocument.querySelectorAll(\".wk-in\").forEach(w=>{\r\n  const src=w.querySelector(\"img.main\").src;\r\n  w.querySelectorAll(\".gl-r,.gl-b\").forEach(i=>i.src=src);\r\n});\r\n\r\n/* magnetic buttons */\r\nif(!reduced && matchMedia(\"(pointer:fine)\").matches){\r\n  document.querySelectorAll(\"#enterBtn,.cta,.moreLink\").forEach(btn=>{\r\n    btn.addEventListener(\"pointermove\",e=>{\r\n      const r=btn.getBoundingClientRect();\r\n      const x=(e.clientX-r.left)/r.width-.5;\r\n      const y=(e.clientY-r.top)/r.height-.5;\r\n      btn.style.transform=`translate(${x*10}px,${y*8}px)`;\r\n    });\r\n    btn.addEventListener(\"pointerleave\",()=>{btn.style.transform=\"\";});\r\n  });\r\n}\r\n\r\n/* philosophy ghost kanji parallax */\r\nconst ghost=document.getElementById(\"ghostTxt\");\r\nif(ghost){\r\n  addEventListener(\"scroll\",()=>{\r\n    const r=ghost.parentElement.getBoundingClientRect();\r\n    const f=(innerHeight-r.top)/(innerHeight+r.height);\r\n    ghost.style.transform=`translateY(${(-50+(f-.5)*30).toFixed(1)}%)`;\r\n  },{passive:true});\r\n}\r\nframe();\r\nsetInterval(()=>{if(document.hidden) frame();},33);\r\n})();";

  function loadThree(){
    if (window.THREE) return Promise.resolve();
    if (window.__vivirisThreePromise) return window.__vivirisThreePromise;
    window.__vivirisThreePromise = new Promise(function(resolve, reject){
      const script = document.createElement('script');
      script.src = THREE_URL;
      script.async = true;
      script.dataset.vivirisThree = 'true';
      script.onload = resolve;
      script.onerror = reject;
      document.head.appendChild(script);
    });
    return window.__vivirisThreePromise;
  }

  class VivirisImmersive extends HTMLElement {
    connectedCallback(){
      if (this.__vivirisMounted) return;
      this.__vivirisMounted = true;
      this.innerHTML = '<style data-viviris-style="true"></style>' + BODY_HTML;
      this.querySelector('style[data-viviris-style="true"]').textContent = STYLE_TEXT;
      const root = this.querySelector('.viviris-custom-element-root');
      if (root) {
        root.style.minHeight = Math.max(window.innerHeight || 900, 900) + 'px';
      }
      const enterExperience = () => {
        if (this.__vivirisEntered) return;
        this.__vivirisEntered = true;
        const welcome = this.querySelector('#welcome');
        const contentRoot = this.querySelector('.viviris-custom-element-root');
        const landing = this.querySelector('#landing');
        const bgm = this.querySelector('#bgm');
        if (welcome) welcome.classList.add('gone');
        document.body.classList.add('entered');
        if (contentRoot) contentRoot.classList.add('entered','user-entered');
        if (landing && typeof landing.focus === 'function') {
          try { landing.focus({ preventScroll: true }); } catch (_) { landing.focus(); }
        }
        if (bgm && typeof bgm.play === 'function') bgm.play().catch(function(){});
      };
      this.addEventListener('click', (event) => {
        const target = event.target && event.target.closest ? event.target.closest('#enterBtn') : null;
        if (!target) return;
        event.preventDefault();
        enterExperience();
      }, true);
      this.addEventListener('keydown', (event) => {
        if ((event.key !== 'Enter' && event.key !== ' ') || !event.target || event.target.id !== 'enterBtn') return;
        event.preventDefault();
        enterExperience();
      }, true);
      const fitToFooter = () => {
        const contentRoot = this.querySelector('.viviris-custom-element-root');
        if (!contentRoot) return;
        const footer = this.querySelector('footer');
        const target = footer || contentRoot;
        const hostTop = this.getBoundingClientRect().top + window.scrollY;
        const targetBottom = target.getBoundingClientRect().bottom + window.scrollY;
        const height = Math.max(window.innerHeight || 900, Math.ceil(targetBottom - hostTop));
        this.style.setProperty('height', height + 'px', 'important');
        this.style.setProperty('min-height', height + 'px', 'important');
        this.dataset.vivirisHeight = String(height);
        requestAnimationFrame(() => {
          const targetBottom = hostTop + height;
          let actualBottom = this.getBoundingClientRect().bottom + window.scrollY;
          let scan = this.parentElement;
          let scanDepth = 0;
          while (scan && scan !== document.body && scan !== document.documentElement && scanDepth < 4) {
            const rect = scan.getBoundingClientRect();
            if (rect.height > height + 24 && rect.height < 120000) {
              actualBottom = Math.max(actualBottom, rect.bottom + window.scrollY);
            }
            scan = scan.parentElement;
            scanDepth += 1;
          }
          const extra = Math.max(0, Math.ceil(actualBottom - targetBottom));
          contentRoot.classList.toggle('wix-oversize', extra > 24);
          contentRoot.style.setProperty('--viviris-extra-height', extra + 'px');
        });
        let parent = this.parentElement;
        let depth = 0;
        while (parent && parent !== document.body && parent !== document.documentElement && depth < 4) {
          const rect = parent.getBoundingClientRect();
          const hostRect = this.getBoundingClientRect();
          const sameColumn = Math.abs(rect.width - hostRect.width) < 80 || rect.width >= hostRect.width;
          if (sameColumn && rect.height > height + 80 && rect.height < 120000) {
            parent.style.setProperty('height', height + 'px', 'important');
            parent.style.setProperty('min-height', height + 'px', 'important');
            parent.dataset.vivirisHeight = String(height);
          }
          parent = parent.parentElement;
          depth += 1;
        }
      };
      const scheduleFitToFooter = () => requestAnimationFrame(fitToFooter);
      fitToFooter();
      requestAnimationFrame(fitToFooter);
      setTimeout(fitToFooter, 400);
      setTimeout(fitToFooter, 1500);
      setTimeout(fitToFooter, 3500);
      window.addEventListener('resize', scheduleFitToFooter, { passive: true });
      this.querySelectorAll('img,video').forEach((media) => {
        media.addEventListener('load', scheduleFitToFooter, { passive: true });
        media.addEventListener('loadedmetadata', scheduleFitToFooter, { passive: true });
      });
      if (window.ResizeObserver && root) {
        new ResizeObserver(scheduleFitToFooter).observe(root);
      }
      loadThree().then(function(){
        try {
          new Function(APP_SCRIPT)();
        } catch (error) {
          window.__vivirisInitError = error && (error.stack || error.message || String(error));
          console.error('[VivirisImmersive] initialization failed', error);
        }
      }).catch(function(error){
        console.error('[VivirisImmersive] Three.js failed to load', error);
      });
    }
  }

  if (!customElements.get(TAG_NAME)) {
    customElements.define(TAG_NAME, VivirisImmersive);
  }
})();
